import { useState } from "react";
import { useAuth } from "@/hooks/useAuth";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Headphones,
  Radio,
  Phone,
  User,
  Clock,
  Mic,
  MicOff,
  Eye,
  PhoneOff,
  Volume2,
  AlertTriangle,
  CalendarDays,
  Coffee,
  PlayCircle,
  Timer,
  Activity,
} from "lucide-react";

export default function MonitoringPage() {
  const { user } = useAuth();
  const isAdmin = user?.role === "admin" || user?.role === "superadmin";
  const companyId = user?.companyId || 1;

  const [listeningSessionId, setListeningSessionId] = useState<number | null>(null);
  const [listeningCallId, setListeningCallId] = useState<number | null>(null);
  const [bargeCallId, setBargeCallId] = useState<number | null>(null);

  // Whisper form states
  const [whisperCallerId, setWhisperCallerId] = useState<string>("");
  const [whisperMessage, setWhisperMessage] = useState("");

  // Queries
  const { data: activeCalls = [] } = trpc.monitoring.activeCalls.useQuery(
    { companyId },
    { 
      enabled: isAdmin,
      refetchInterval: 3000 // Poll active calls every 3 seconds
    }
  );

  const { data: users = [] } = trpc.user.list.useQuery(undefined, { enabled: isAdmin });
  const { data: campaigns = [] } = trpc.campaign.list.useQuery(undefined, { enabled: isAdmin });

  // ── Date-wise Caller Day Report ──
  const todayStr = new Date().toISOString().slice(0, 10);
  const [reportCallerId, setReportCallerId] = useState<string>("");
  const [reportDate, setReportDate] = useState<string>(todayStr);
  const { data: dayReport, isFetching: reportLoading } = trpc.monitoring.callerDayReport.useQuery(
    { callerId: parseInt(reportCallerId) || 0, date: reportDate },
    { enabled: isAdmin && !!reportCallerId && !!reportDate }
  );
  const callerUsers = users.filter((u: any) => u.role === "caller" || u.role === "admin");

  const fmtSecs = (secs: number) => {
    const h = Math.floor(secs / 3600);
    const m = Math.floor((secs % 3600) / 60);
    const sec = secs % 60;
    if (h > 0) return `${h}h ${m}m ${sec}s`;
    if (m > 0) return `${m}m ${sec}s`;
    return `${sec}s`;
  };
  const fmtTime = (iso: string | null) =>
    iso ? new Date(iso).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" }) : "—";

  // Mutations
  const startListeningMutation = trpc.monitoring.startListening.useMutation();
  const stopListeningMutation = trpc.monitoring.stopListening.useMutation();
  const bargeInMutation = trpc.monitoring.bargeIn.useMutation();
  const whisperMutation = trpc.monitoring.whisper.useMutation();

  const handleListen = async (callId: number, callerId: number) => {
    try {
      const res = await startListeningMutation.mutateAsync({ callId, callerId });
      setListeningSessionId(res.id);
      setListeningCallId(callId);
      setBargeCallId(null);
    } catch (err) {
      console.error("Failed to start listening:", err);
    }
  };

  const handleStopListening = async () => {
    if (listeningSessionId) {
      try {
        await stopListeningMutation.mutateAsync({ sessionId: listeningSessionId });
      } catch (err) {
        console.error("Failed to stop listening:", err);
      }
    }
    setListeningSessionId(null);
    setListeningCallId(null);
    setBargeCallId(null);
  };

  const handleBargeIn = async (callId: number, callerId: number) => {
    try {
      const res = await bargeInMutation.mutateAsync({ callId, callerId });
      setListeningSessionId(res.id);
      setListeningCallId(callId);
      setBargeCallId(callId);
    } catch (err) {
      console.error("Failed to barge in:", err);
    }
  };

  const handleSendWhisper = async () => {
    if (!whisperCallerId || !whisperMessage.trim()) return;
    const callerId = parseInt(whisperCallerId);
    const targetCall = activeCalls.find((c: any) => c.callerId === callerId);
    if (!targetCall) {
      alert("No active call found for this caller.");
      return;
    }
    try {
      await whisperMutation.mutateAsync({
        callerId,
        callId: targetCall.id,
        message: whisperMessage,
      });
      setWhisperMessage("");
      alert("Whisper message sent privately to caller.");
    } catch (err) {
      console.error("Failed to whisper:", err);
    }
  };

  const formatDuration = (startedAt: string | null) => {
    if (!startedAt) return "00:00";
    const diffMs = Date.now() - new Date(startedAt).getTime();
    const diffSecs = Math.max(0, Math.floor(diffMs / 1000));
    const mins = Math.floor(diffSecs / 60);
    const secs = diffSecs % 60;
    return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`;
  };

  // Lead details resolver matching db.json initial seed
  const getLeadDetails = (leadId: number) => {
    const leadsMap: Record<number, { name: string; company: string }> = {
      1: { name: "Sundar Pichai", company: "Google" },
      2: { name: "Satya Nadella", company: "Microsoft" },
      3: { name: "Tim Cook", company: "Apple" },
      4: { name: "Mark Zuckerberg", company: "Meta" }
    };
    return leadsMap[leadId] || { name: `Lead #${leadId}`, company: "Enterprise Target" };
  };

  if (!isAdmin) {
    return (
      <div className="flex items-center justify-center h-64">
        <AlertTriangle className="w-8 h-8 text-amber-400 mr-3" />
        <p className="text-gray-400">Monitoring is only available for admin users.</p>
      </div>
    );
  }

  const activeListeningCall = activeCalls.find((c: any) => c.id === listeningCallId);
  const activeListeningLead = activeListeningCall ? getLeadDetails(activeListeningCall.leadId) : null;
  const activeListeningCaller = activeListeningCall ? users.find((u: any) => u.id === activeListeningCall.callerId) : null;

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Live Monitoring</h1>
          <p className="text-gray-400 mt-1">Listen to active calls in real-time without permission</p>
        </div>
        <div className="flex items-center gap-2 px-4 py-2 bg-gray-900 rounded-lg border border-gray-800">
          <Radio className="w-4 h-4 text-green-400 animate-pulse" />
          <span className="text-sm text-gray-300">{activeCalls.length} active calls</span>
        </div>
      </div>

      {/* Active Monitoring Sessions */}
      {listeningCallId && activeListeningCall && (
        <Card className="bg-gray-900 border-blue-800/50">
          <CardContent className="p-4">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-full bg-blue-500/20 flex items-center justify-center animate-pulse">
                <Headphones className="w-6 h-6 text-blue-400" />
              </div>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <p className="text-white font-medium">Listening to call #{listeningCallId}</p>
                  <Badge className="bg-blue-500/20 text-blue-400 animate-pulse">Live</Badge>
                </div>
                <p className="text-sm text-gray-400">
                  {activeListeningCaller?.name || `Caller ${activeListeningCall.callerId}`} → {activeListeningLead?.name} ({activeListeningLead?.company})
                </p>
              </div>
              <div className="flex items-center gap-2">
                <Volume2 className="w-5 h-5 text-green-400" />
                {!bargeCallId && (
                  <Button
                    variant="outline"
                    size="sm"
                    className="border-purple-600/30 text-purple-400 hover:bg-purple-600/20"
                    onClick={() => handleBargeIn(activeListeningCall.id, activeListeningCall.callerId)}
                  >
                    <Mic className="w-4 h-4 mr-1" /> Barge In
                  </Button>
                )}
                <Button
                  variant="outline"
                  size="sm"
                  className="border-red-600/30 text-red-400 hover:bg-red-600/20"
                  onClick={handleStopListening}
                >
                  <PhoneOff className="w-4 h-4 mr-1" /> Stop
                </Button>
              </div>
            </div>
            {bargeCallId && (
              <div className="mt-3 p-3 bg-purple-500/10 rounded-lg border border-purple-500/20">
                <div className="flex items-center gap-2">
                  <Mic className="w-4 h-4 text-purple-400" />
                  <p className="text-sm text-purple-300 font-medium">Barge Mode Active</p>
                  <Badge className="bg-purple-500/20 text-purple-400 text-xs animate-pulse">Speaking</Badge>
                </div>
                <p className="text-xs text-purple-400/70 mt-1">Both caller and lead can hear you</p>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Active Calls Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {activeCalls.map((call: any) => {
          const caller = users.find((u: any) => u.id === call.callerId);
          const lead = getLeadDetails(call.leadId);
          const campaign = campaigns.find((c: any) => c.id === call.campaignId);

          return (
            <Card key={call.id} className={`bg-gray-900 border-gray-800 ${listeningCallId === call.id ? "ring-1 ring-blue-600" : ""}`}>
              <CardContent className="p-4">
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-green-500/20 flex items-center justify-center">
                      <Phone className="w-5 h-5 text-green-400" />
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-medium text-white">{caller?.name || `Caller ${call.callerId}`}</p>
                        <Badge className="bg-gray-700 text-gray-300 text-xs">ID: {call.callerId}</Badge>
                      </div>
                      <p className="text-xs text-gray-500 flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {formatDuration(call.startedAt)}
                      </p>
                    </div>
                  </div>
                  <Badge className={call.status === "connected" ? "bg-green-500/20 text-green-400 animate-pulse" : "bg-blue-500/20 text-blue-400"}>
                    {call.status}
                  </Badge>
                </div>

                <div className="bg-gray-800/50 rounded-lg p-3 mb-3">
                  <div className="flex items-center gap-2 mb-1">
                    <User className="w-4 h-4 text-gray-500" />
                    <span className="text-sm text-gray-300">{lead.name}</span>
                    <span className="text-xs text-gray-500">| {lead.company}</span>
                  </div>
                  <p className="text-xs text-gray-500 ml-6">{call.toNumber}</p>
                </div>

                <div className="flex items-center justify-between">
                  <span className="text-xs text-gray-500">{campaign?.name || "Manual Dialer"}</span>
                  <div className="flex gap-2">
                    {listeningCallId === call.id ? (
                      <Button
                        variant="outline"
                        size="sm"
                        className="border-red-600/30 text-red-400 hover:bg-red-600/20 h-8"
                        onClick={handleStopListening}
                      >
                        <MicOff className="w-4 h-4 mr-1" /> Stop
                      </Button>
                    ) : (
                      <>
                        <Button
                          variant="outline"
                          size="sm"
                          className="border-blue-600/30 text-blue-400 hover:bg-blue-600/20 h-8"
                          onClick={() => handleListen(call.id, call.callerId)}
                        >
                          <Eye className="w-4 h-4 mr-1" /> Listen
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          className="border-purple-600/30 text-purple-400 hover:bg-purple-600/20 h-8"
                          onClick={() => handleBargeIn(call.id, call.callerId)}
                        >
                          <Mic className="w-4 h-4 mr-1" /> Barge
                        </Button>
                      </>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          );
        })}
        {activeCalls.length === 0 && (
          <div className="col-span-2 text-center py-12 text-gray-500">
            No active calls currently in progress.
          </div>
        )}
      </div>

      {/* Whisper Feature */}
      <Card className="bg-gray-900 border-gray-800">
        <CardHeader>
          <CardTitle className="text-white text-base">Whisper to Caller</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-gray-400 mb-3">
            Send a private message to a caller that only they can hear. The lead will not hear this message.
          </p>
          <div className="flex flex-col sm:flex-row gap-2">
            <select 
              value={whisperCallerId}
              onChange={(e) => setWhisperCallerId(e.target.value)}
              className="bg-gray-800 border border-gray-700 rounded-md px-3 py-2 text-sm text-white"
            >
              <option value="">Select caller...</option>
              {activeCalls.map((c: any) => {
                const callerObj = users.find((u: any) => u.id === c.callerId);
                return (
                  <option key={c.callerId} value={c.callerId}>
                    {callerObj?.name || `Caller ${c.callerId}`} (Call #{c.id})
                  </option>
                );
              })}
            </select>
            <input
              type="text"
              value={whisperMessage}
              onChange={(e) => setWhisperMessage(e.target.value)}
              placeholder="Type message..."
              className="flex-1 bg-gray-800 border border-gray-700 rounded-md px-3 py-2 text-sm text-white"
            />
            <Button size="sm" className="bg-blue-600 hover:bg-blue-700 h-auto" onClick={handleSendWhisper}>
              <Headphones className="w-4 h-4 mr-1" /> Send Whisper
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* ─── Date-wise Caller Day Report ─── */}
      <Card className="bg-gray-900 border-gray-800">
        <CardHeader>
          <CardTitle className="text-white text-lg flex items-center gap-2">
            <CalendarDays className="w-5 h-5 text-blue-400" /> Caller Day Report (Date-wise)
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex flex-col sm:flex-row gap-3">
            <select
              value={reportCallerId}
              onChange={(e) => setReportCallerId(e.target.value)}
              className="bg-gray-800 border border-gray-700 rounded-md px-3 py-2 text-sm text-white"
            >
              <option value="">Select caller...</option>
              {callerUsers.map((u: any) => (
                <option key={u.id} value={u.id}>{u.name || u.email || `User #${u.id}`}</option>
              ))}
            </select>
            <input
              type="date"
              value={reportDate}
              max={todayStr}
              onChange={(e) => setReportDate(e.target.value)}
              className="bg-gray-800 border border-gray-700 rounded-md px-3 py-2 text-sm text-white"
            />
            {reportLoading && <span className="text-sm text-gray-500 self-center animate-pulse">Loading report...</span>}
          </div>

          {dayReport && reportCallerId && (
            <>
              {/* Summary Cards */}
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
                <div className="bg-gray-800/60 rounded-lg p-3 text-center">
                  <Clock className="w-4 h-4 text-blue-400 mx-auto mb-1" />
                  <p className="text-sm font-bold text-white">{fmtTime(dayReport.dayStartTime)}</p>
                  <p className="text-[10px] text-gray-400">Day Start (1st Call)</p>
                </div>
                <div className="bg-gray-800/60 rounded-lg p-3 text-center">
                  <Clock className="w-4 h-4 text-purple-400 mx-auto mb-1" />
                  <p className="text-sm font-bold text-white">{fmtTime(dayReport.dayEndTime)}</p>
                  <p className="text-[10px] text-gray-400">Last Activity</p>
                </div>
                <div className="bg-gray-800/60 rounded-lg p-3 text-center">
                  <Phone className="w-4 h-4 text-green-400 mx-auto mb-1" />
                  <p className="text-sm font-bold text-white">{dayReport.totalCalls}</p>
                  <p className="text-[10px] text-gray-400">Total Calls ({dayReport.connectedCalls} connected)</p>
                </div>
                <div className="bg-gray-800/60 rounded-lg p-3 text-center">
                  <Timer className="w-4 h-4 text-cyan-400 mx-auto mb-1" />
                  <p className="text-sm font-bold text-white">{fmtSecs(dayReport.totalTalkTime)}</p>
                  <p className="text-[10px] text-gray-400">Total Talk Time</p>
                </div>
                <div className="bg-gray-800/60 rounded-lg p-3 text-center">
                  <Coffee className="w-4 h-4 text-amber-400 mx-auto mb-1" />
                  <p className="text-sm font-bold text-white">{fmtSecs(dayReport.totalIdleTime)}</p>
                  <p className="text-[10px] text-gray-400">Free / Pause Time</p>
                </div>
                <div className="bg-gray-800/60 rounded-lg p-3 text-center">
                  <Activity className="w-4 h-4 text-rose-400 mx-auto mb-1" />
                  <p className="text-sm font-bold text-white">{fmtSecs(dayReport.avgCallDuration)}</p>
                  <p className="text-[10px] text-gray-400">Avg Call Duration</p>
                </div>
              </div>

              {/* Timeline */}
              {dayReport.timeline.length === 0 ? (
                <div className="text-center py-8 text-gray-500 text-sm">
                  No calls recorded on {reportDate} for this caller.
                </div>
              ) : (
                <div className="space-y-2 max-h-[480px] overflow-y-auto pr-2">
                  {dayReport.timeline.map((item: any, i: number) =>
                    item.type === "idle" ? (
                      <div key={i} className="flex items-center gap-3 pl-6 py-1">
                        <div className="w-px h-6 bg-amber-600/40 ml-3" />
                        <Coffee className="w-3.5 h-3.5 text-amber-500" />
                        <span className="text-xs text-amber-400/90">
                          Free / Pause — {fmtSecs(item.seconds)} ({fmtTime(item.from)} → {fmtTime(item.to)})
                        </span>
                      </div>
                    ) : (
                      <div key={i} className="bg-gray-800/40 border border-gray-800 rounded-lg p-3">
                        <div className="flex flex-wrap items-center justify-between gap-2">
                          <div className="flex items-center gap-3">
                            <div className="w-7 h-7 rounded-full bg-blue-600/20 flex items-center justify-center text-xs font-bold text-blue-400">
                              #{item.callNumber}
                            </div>
                            <div>
                              <p className="text-sm text-white font-medium">
                                {item.toNumber}{" "}
                                <Badge className={`ml-1 text-[10px] ${
                                  item.status === "completed" || item.status === "connected"
                                    ? "bg-green-500/20 text-green-400"
                                    : "bg-gray-600/30 text-gray-400"
                                }`}>{item.status}</Badge>
                                <Badge className="ml-1 text-[10px] bg-purple-500/20 text-purple-400">{item.callType}</Badge>
                              </p>
                              <p className="text-[11px] text-gray-500">
                                {fmtTime(item.startedAt)} → {fmtTime(item.endedAt)} · Duration: {fmtSecs(item.duration)}
                              </p>
                            </div>
                          </div>
                          {item.recordingUrl ? (
                            <audio controls src={item.recordingUrl} className="h-8 max-w-[220px]" />
                          ) : (
                            <span className="text-[10px] text-gray-600 flex items-center gap-1">
                              <PlayCircle className="w-3 h-3" /> No recording
                            </span>
                          )}
                        </div>
                        {item.notes && (
                          <p className="text-xs text-gray-400 italic mt-2 border-t border-gray-800 pt-2">{item.notes}</p>
                        )}
                      </div>
                    )
                  )}
                </div>
              )}
            </>
          )}
          {!reportCallerId && (
            <p className="text-sm text-gray-500 text-center py-4">
              Select a caller and a date to view their complete day performance — start time, every call with duration and recording, plus all free/pause gaps.
            </p>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { useAuth } from "@/hooks/useAuth";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Phone,
  Download,
  Calendar,
  FileSpreadsheet,
  CheckCircle2,
  Clock,
  TrendingUp,
  PieChart,
} from "lucide-react";

export default function ReportsPage() {
  const { user } = useAuth();
  const companyId = user?.companyId || 1;
  const isAdmin = user?.role === "admin" || user?.role === "superadmin";

  const [dateRange, setDateRange] = useState("7d");

  const daysParam = 
    dateRange === "today" ? 1 :
    dateRange === "7d" ? 7 :
    dateRange === "30d" ? 30 : 90;

  // Queries
  const { data: adminStats } = trpc.report.dashboard.useQuery(
    { companyId },
    { enabled: isAdmin }
  );

  const { data: callVolume = [] } = trpc.report.callVolume.useQuery(
    { companyId, days: daysParam },
    { enabled: isAdmin }
  );

  const { data: rawDispositions = [] } = trpc.report.dispositionBreakdown.useQuery(
    { companyId },
    { enabled: isAdmin }
  );

  const { data: agentPerformance = [] } = trpc.report.agentPerformance.useQuery(
    { companyId },
    { enabled: isAdmin }
  );

  const { data: campaigns = [] } = trpc.campaign.list.useQuery(
    undefined,
    { enabled: isAdmin }
  );

  const { data: users = [] } = trpc.user.list.useQuery(
    undefined,
    { enabled: isAdmin }
  );

  const exportCallsMutation = trpc.report.exportCalls.useMutation();

  const handleExportCSV = async () => {
    try {
      const res = await exportCallsMutation.mutateAsync({
        companyId,
        format: "csv",
      });
      alert(`Export generated successfully! Download started. Generated at: ${new Date(res.generatedAt).toLocaleString()}`);
    } catch (err) {
      console.error("Export failed:", err);
    }
  };

  // Disposition metadata mapping
  const dispositionMap: Record<number, { label: string; color: string }> = {
    1: { label: "Connected", color: "bg-green-500" },
    2: { label: "No Answer", color: "bg-red-500" },
    3: { label: "Answering Machine", color: "bg-amber-500" },
    4: { label: "Voice Mail", color: "bg-purple-500" },
    5: { label: "Wrong Number", color: "bg-pink-500" },
    6: { label: "Invalid/Irrelevant", color: "bg-gray-500" },
    7: { label: "Interested", color: "bg-emerald-500" },
    8: { label: "Not Interested", color: "bg-rose-500" },
    9: { label: "Do Not Call", color: "bg-red-800" },
    10: { label: "Custom Outcome", color: "bg-blue-600" }
  };

  const totalDispCount = rawDispositions.reduce((a, b) => a + (b.count || 0), 0);
  const dispositionData = rawDispositions.map((d: any) => {
    const meta = dispositionMap[d.dispositionId] || { label: `Outcome #${d.dispositionId}`, color: "bg-gray-600" };
    const pct = totalDispCount > 0 ? Math.round((d.count / totalDispCount) * 100) : 0;
    return {
      label: meta.label,
      count: d.count,
      pct,
      color: meta.color,
    };
  });

  const getStatusBadge = (status: string) => {
    const colors: Record<string, string> = {
      running: "bg-green-500/20 text-green-400",
      paused: "bg-amber-500/20 text-amber-400",
      completed: "bg-blue-500/20 text-blue-400",
      draft: "bg-gray-500/20 text-gray-400",
    };
    return <Badge className={`${colors[status] || "bg-gray-500/20"} border-0 capitalize`}>{status}</Badge>;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Reports & Analytics</h1>
          <p className="text-gray-400 mt-1">Detailed call analytics and performance reports</p>
        </div>
        <div className="flex gap-2">
          <Select value={dateRange} onValueChange={setDateRange}>
            <SelectTrigger className="w-36 bg-gray-900 border-gray-800 text-white">
              <Calendar className="w-4 h-4 mr-2" />
              <SelectValue />
            </SelectTrigger>
            <SelectContent className="bg-gray-900 border-gray-800">
              <SelectItem value="today">Today</SelectItem>
              <SelectItem value="7d">Last 7 Days</SelectItem>
              <SelectItem value="30d">Last 30 Days</SelectItem>
              <SelectItem value="90d">Last 90 Days</SelectItem>
            </SelectContent>
          </Select>
          <Button 
            variant="outline" 
            onClick={handleExportCSV}
            className="border-gray-700 text-gray-300 hover:text-white hover:bg-gray-800"
          >
            <Download className="w-4 h-4 mr-2" />
            Export CSV
          </Button>
        </div>
      </div>

      <Tabs defaultValue="overview">
        <TabsList className="bg-gray-900 border border-gray-800">
          <TabsTrigger value="overview" className="data-[state=active]:bg-gray-800">Overview</TabsTrigger>
          <TabsTrigger value="agents" className="data-[state=active]:bg-gray-800">Agent Performance</TabsTrigger>
          <TabsTrigger value="campaigns" className="data-[state=active]:bg-gray-800">Campaigns</TabsTrigger>
          <TabsTrigger value="dispositions" className="data-[state=active]:bg-gray-800">Dispositions</TabsTrigger>
        </TabsList>

        <TabsContent value="overview" className="mt-4 space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-4 gap-4">
            <Card className="bg-gray-900 border-gray-800">
              <CardContent className="p-4 flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg bg-blue-500/10 flex items-center justify-center">
                  <Phone className="w-5 h-5 text-blue-400" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-white">{(adminStats?.totalCalls || 0).toLocaleString()}</p>
                  <p className="text-sm text-gray-400">Total Calls</p>
                </div>
              </CardContent>
            </Card>
            <Card className="bg-gray-900 border-gray-800">
              <CardContent className="p-4 flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg bg-green-500/10 flex items-center justify-center">
                  <CheckCircle2 className="w-5 h-5 text-green-400" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-white">{adminStats?.connectionRate || 0}%</p>
                  <p className="text-sm text-gray-400">Connection Rate</p>
                </div>
              </CardContent>
            </Card>
            <Card className="bg-gray-900 border-gray-800">
              <CardContent className="p-4 flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg bg-purple-500/10 flex items-center justify-center">
                  <Clock className="w-5 h-5 text-purple-400" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-white">2m 45s</p>
                  <p className="text-sm text-gray-400">Avg Duration</p>
                </div>
              </CardContent>
            </Card>
            <Card className="bg-gray-900 border-gray-800">
              <CardContent className="p-4 flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg bg-amber-500/10 flex items-center justify-center">
                  <TrendingUp className="w-5 h-5 text-amber-400" />
                </div>
                <div>
                  <p className="text-2xl font-bold text-white">{(adminStats?.activeCampaigns || 0).toLocaleString()}</p>
                  <p className="text-sm text-gray-400">Active Campaigns</p>
                </div>
              </CardContent>
            </Card>
          </div>

          <Card className="bg-gray-900 border-gray-800">
            <CardHeader>
              <CardTitle className="text-white text-base">Call Volume</CardTitle>
            </CardHeader>
            <CardContent>
              {callVolume.length > 0 ? (
                <div className="h-64 flex items-end justify-around gap-3 px-4">
                  {callVolume.map((d: any, i: number) => {
                    const maxVal = Math.max(...callVolume.map((x: any) => x.total || 1));
                    const totalH = (d.total / maxVal) * 200;
                    const connH = (d.connected / maxVal) * 200;
                    const dateLabel = d.date.includes("-") ? d.date.split("-").slice(1).join("-") : d.date;

                    return (
                      <div key={i} className="flex-1 flex flex-col items-center gap-2">
                        <div className="w-full flex flex-col gap-1 items-center justify-end h-52">
                          <div
                            className="w-full bg-green-500/60 rounded-t"
                            style={{ height: `${connH}px` }}
                            title={`Connected: ${d.connected}`}
                          />
                          <div
                            className="w-full bg-blue-500/40 rounded-t"
                            style={{ height: `${Math.max(0, totalH - connH)}px` }}
                            title={`Total Calls: ${d.total}`}
                          />
                        </div>
                        <span className="text-xs text-gray-500">{dateLabel}</span>
                      </div>
                    );
                  })}
                </div>
              ) : (
                <div className="h-64 flex items-center justify-center text-gray-500">
                  No call volume logs found in selected date range.
                </div>
              )}
              <div className="flex gap-4 justify-center mt-4 text-xs">
                <span className="flex items-center gap-1 text-gray-400"><div className="w-3 h-3 bg-green-500/60 rounded" /> Connected</span>
                <span className="flex items-center gap-1 text-gray-400"><div className="w-3 h-3 bg-blue-500/40 rounded" /> Total</span>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="agents" className="mt-4">
          <Card className="bg-gray-900 border-gray-800">
            <CardContent className="p-0">
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-gray-800">
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Agent</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Calls</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Connected</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Avg Duration</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {agentPerformance.map((agent: any, i: number) => {
                      const userObj = users.find((u: any) => u.id === agent.callerId);
                      const name = userObj?.name || `Caller #${agent.callerId}`;
                      const status = userObj?.status || "active";

                      return (
                        <tr key={i} className="border-b border-gray-800/50 hover:bg-gray-800/30">
                          <td className="px-4 py-3 text-sm font-medium text-white">{name}</td>
                          <td className="px-4 py-3 text-sm text-gray-400">{agent.totalCalls}</td>
                          <td className="px-4 py-3 text-sm text-green-400">{agent.connectedCalls}</td>
                          <td className="px-4 py-3 text-sm text-gray-400">{agent.avgDuration || 0}s</td>
                          <td className="px-4 py-3">
                            <Badge className={status === "active" ? "bg-green-500/20 text-green-400" : "bg-gray-500/20 text-gray-400"}>
                              {status}
                            </Badge>
                          </td>
                        </tr>
                      );
                    })}
                    {agentPerformance.length === 0 && (
                      <tr>
                        <td colSpan={5} className="text-center py-8 text-gray-500">
                          No agent calling performance logs found.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="campaigns" className="mt-4">
          <Card className="bg-gray-900 border-gray-800">
            <CardContent className="p-0">
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-gray-800">
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Campaign</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Type</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Total Leads</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Completed</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Success Calls</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {campaigns.map((camp: any, i: number) => {
                      return (
                        <tr key={i} className="border-b border-gray-800/50 hover:bg-gray-800/30">
                          <td className="px-4 py-3 text-sm font-medium text-white">{camp.name}</td>
                          <td className="px-4 py-3">
                            <Badge className="bg-gray-700 text-gray-300 capitalize">{camp.type}</Badge>
                          </td>
                          <td className="px-4 py-3 text-sm text-gray-400">{(camp.totalLeads || 0).toLocaleString()}</td>
                          <td className="px-4 py-3 text-sm text-gray-400">{(camp.completedLeads || 0).toLocaleString()}</td>
                          <td className="px-4 py-3 text-sm text-green-400">{(camp.successfulCalls || 0).toLocaleString()}</td>
                          <td className="px-4 py-3">
                            {getStatusBadge(camp.status)}
                          </td>
                        </tr>
                      );
                    })}
                    {campaigns.length === 0 && (
                      <tr>
                        <td colSpan={6} className="text-center py-8 text-gray-500">
                          No campaign statistics found.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="dispositions" className="mt-4">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <Card className="bg-gray-900 border-gray-800">
              <CardHeader>
                <CardTitle className="text-white text-base">Disposition Breakdown</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {dispositionData.map((d: any, i: number) => (
                    <div key={i}>
                      <div className="flex items-center justify-between text-sm mb-1">
                        <span className="text-gray-300">{d.label}</span>
                        <span className="text-gray-400">{(d.count || 0).toLocaleString()} ({d.pct}%)</span>
                      </div>
                      <div className="w-full bg-gray-800 rounded-full h-2">
                        <div className={`${d.color} h-2 rounded-full`} style={{ width: `${d.pct}%` }} />
                      </div>
                    </div>
                  ))}
                  {dispositionData.length === 0 && (
                    <p className="text-center py-8 text-gray-500 text-sm">No disposition breakdowns recorded.</p>
                  )}
                </div>
              </CardContent>
            </Card>
            <Card className="bg-gray-900 border-gray-800">
              <CardHeader>
                <CardTitle className="text-white text-base">Export and Analytics</CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <Button 
                  variant="outline" 
                  onClick={handleExportCSV}
                  className="w-full justify-start border-gray-700 text-gray-300 hover:text-white hover:bg-gray-800"
                >
                  <FileSpreadsheet className="w-4 h-4 mr-3 text-green-400" />
                  Export calls to CSV
                </Button>
                <Button 
                  variant="outline" 
                  onClick={handleExportCSV}
                  className="w-full justify-start border-gray-700 text-gray-300 hover:text-white hover:bg-gray-800"
                >
                  <PieChart className="w-4 h-4 mr-3 text-purple-400" />
                  Generate custom PDF report
                </Button>
                <div className="pt-3 border-t border-gray-800">
                  <h4 className="text-sm font-medium text-gray-300 mb-2">Campaign Filter List</h4>
                  <div className="space-y-2">
                    {campaigns.map((c: any) => (
                      <label key={c.id} className="flex items-center gap-2 text-sm text-gray-400">
                        <input type="checkbox" defaultChecked className="rounded border-gray-600 bg-gray-800" />
                        {c.name}
                      </label>
                    ))}
                    {campaigns.length === 0 && (
                      <p className="text-xs text-gray-500">No campaigns created yet.</p>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useEffect, useMemo } from "react";
import { useAuth } from "@/hooks/useAuth";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
  Phone,
  Save,
  Trash2,
  Edit,
  Radio,
  CheckCircle,
  XCircle,
  Loader2,
  Plus,
  X,
  PhoneCall,
  PhoneIncoming,
} from "lucide-react";

type CredentialForm = {
  phoneNumber: string;
  sipUsername: string;
  sipPassword: string;
  apiKey: string;
  sipHost: string;
  connectionId: string;
  enabled: boolean;
};

const EMPTY_FORM: CredentialForm = {
  phoneNumber: "",
  sipUsername: "",
  sipPassword: "",
  apiKey: "",
  sipHost: "",
  connectionId: "",
  enabled: true,
};

type TestState = "idle" | "loading" | "ok" | "error";
type TestResult = {
  outgoing: TestState;
  incoming: TestState;
  outgoingMessage: string;
  incomingMessage: string;
};

// id = 0 is the sentinel for the Telnyx-config-derived synthetic entry
type DisplayEntry = {
  id: number;
  number: string;
  label?: string;
  status: "active" | "inactive";
  synthetic?: boolean;
};

export default function SettingsPage() {
  const { user } = useAuth();
  const isAdmin = user?.role === "admin" || user?.role === "superadmin";

  const telnyxQuery   = trpc.integration.getTelnyx.useQuery(undefined, { enabled: isAdmin });
  const numbersQuery  = trpc.integration.listPhoneNumbers.useQuery(undefined, { enabled: isAdmin });

  const testTelnyxMutation        = trpc.integration.testTelnyx.useMutation();
  const saveTelnyxMutation        = trpc.integration.saveTelnyx.useMutation({
    onSuccess: () => { telnyxQuery.refetch(); numbersQuery.refetch(); },
  });
  const addPhoneMutation          = trpc.integration.addPhoneNumber.useMutation({
    onSuccess: () => numbersQuery.refetch(),
  });
  const updatePhoneNumberMutation = trpc.integration.updatePhoneNumber.useMutation({
    onSuccess: () => numbersQuery.refetch(),
  });
  const removePhoneMutation       = trpc.integration.removePhoneNumber.useMutation({
    onSuccess: () => numbersQuery.refetch(),
  });

  const [showForm,   setShowForm]   = useState(false);
  // null = new entry | 0 = editing synthetic Telnyx entry | >0 = editing real phoneNumber
  const [editingId,  setEditingId]  = useState<number | null>(null);
  const [form,       setForm]       = useState<CredentialForm>(EMPTY_FORM);
  const [testResult, setTestResult] = useState<TestResult>({
    outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "",
  });
  const [saveStatus, setSaveStatus] = useState<{ type: "idle" | "ok" | "error"; message: string }>({
    type: "idle", message: "",
  });

  // ── Build display list ─────────────────────────────────────────────────────
  // If the Telnyx config has a defaultCallerId that is not yet stored in the
  // phoneNumbers array (legacy save path), show it as a synthetic row so the
  // user can always see and edit what they configured.
  const phoneNumbers: DisplayEntry[] = useMemo(() => {
    const real: DisplayEntry[] = (numbersQuery.data ?? []).map((n: any) => ({
      id: n.id,
      number: n.number,
      label: n.label ?? n.name,   // backward-compat with old "name" field
      status: n.status as "active" | "inactive",
    }));

    const telnyxNumber   = telnyxQuery.data?.defaultCallerId?.trim();
    const telnyxUsername = telnyxQuery.data?.sipUsername?.trim();

    if (telnyxNumber && !real.some((n) => n.number === telnyxNumber)) {
      real.unshift({
        id: 0,
        number: telnyxNumber,
        label: telnyxUsername || undefined,
        status: telnyxQuery.data?.enabled ? "active" : "inactive",
        synthetic: true,
      });
    }

    return real;
  }, [numbersQuery.data, telnyxQuery.data]);

  // ── Pre-populate form when editing ────────────────────────────────────────
  useEffect(() => {
    if (editingId === null || !telnyxQuery.data) return;
    const saved = telnyxQuery.data;

    if (editingId === 0) {
      // Synthetic entry — load straight from Telnyx config
      setForm({
        phoneNumber: saved.defaultCallerId || "",
        sipUsername: saved.sipUsername || "",
        sipPassword: "",
        apiKey: "",
        sipHost: saved.sipHost || "",
        connectionId: saved.connectionId || "",
        enabled: saved.enabled ?? true,
      });
    } else {
      // Real phoneNumbers entry
      const num = (numbersQuery.data ?? []).find((n: any) => n.id === editingId) as any;
      setForm({
        phoneNumber: num?.number || saved.defaultCallerId || "",
        sipUsername: num?.label ?? num?.name ?? saved.sipUsername ?? "",
        sipPassword: "",
        apiKey: "",
        sipHost: saved.sipHost || "",
        connectionId: saved.connectionId || "",
        enabled: saved.enabled ?? true,
      });
    }
  }, [editingId, telnyxQuery.data, numbersQuery.data]);

  // ── Form completeness (controls whether Test button appears) ───────────────
  const isFormComplete =
    form.phoneNumber.trim() !== "" &&
    form.sipUsername.trim() !== "" &&
    (form.sipPassword.trim() !== "" || (editingId !== null && !!telnyxQuery.data?.hasSipPassword)) &&
    (form.apiKey.trim() !== "" || !!telnyxQuery.data?.hasApiKey);

  // ── Handlers ──────────────────────────────────────────────────────────────
  const handleTest = async () => {
    setTestResult({
      outgoing: "loading", incoming: "loading",
      outgoingMessage: "Connecting to Telnyx…",
      incomingMessage: "Verifying SIP registration…",
    });
    try {
      const res = await testTelnyxMutation.mutateAsync({ apiKey: form.apiKey || undefined });
      if (res.ok) {
        setTestResult({
          outgoing: "ok", incoming: "ok",
          outgoingMessage: `Outgoing ready — ${res.connections.length} connection(s) found`,
          incomingMessage: "Incoming verified — SIP credentials accepted",
        });
      } else {
        setTestResult({
          outgoing: "error", incoming: "error",
          outgoingMessage: res.message || "Outgoing test failed",
          incomingMessage: "Could not verify incoming — check SIP credentials",
        });
      }
    } catch (e) {
      const msg = e instanceof Error ? e.message : "Connection failed";
      setTestResult({
        outgoing: "error", incoming: "error",
        outgoingMessage: msg, incomingMessage: "Could not verify incoming",
      });
    }
  };

  const handleSave = async () => {
    try {
      // 1. Always update the global Telnyx config (API key, SIP creds, connection)
      await saveTelnyxMutation.mutateAsync({
        apiKey:         form.apiKey || undefined,
        connectionId:   form.connectionId,
        connectionName: form.sipUsername,
        defaultCallerId: form.phoneNumber,
        sipUsername:    form.sipUsername,
        sipPassword:    form.sipPassword || undefined,
        sipHost:        form.sipHost,
        webrtcEnabled:  true,
        enabled:        form.enabled,
      });

      // 2a. New credential → create a phoneNumbers entry
      if (editingId === null) {
        await addPhoneMutation.mutateAsync({
          number: form.phoneNumber,
          label:  form.sipUsername,
        });
      }
      // 2b. Synthetic (Telnyx defaultCallerId not yet in phoneNumbers) → create it now
      else if (editingId === 0) {
        await addPhoneMutation.mutateAsync({
          number: form.phoneNumber,
          label:  form.sipUsername,
        });
      }
      // 2c. Real entry → update its label (number is read-only in edit mode)
      else {
        await updatePhoneNumberMutation.mutateAsync({
          id:    editingId,
          label: form.sipUsername,
        });
      }

      setSaveStatus({ type: "ok", message: "Credential saved successfully." });
      setTimeout(() => {
        closeForm();
        setSaveStatus({ type: "idle", message: "" });
      }, 1200);
    } catch (e) {
      setSaveStatus({ type: "error", message: e instanceof Error ? e.message : "Failed to save." });
    }
  };

  const openEdit = (id: number) => {
    setEditingId(id);
    setShowForm(true);
    setTestResult({ outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "" });
    setSaveStatus({ type: "idle", message: "" });
  };

  const closeForm = () => {
    setShowForm(false);
    setEditingId(null);
    setForm(EMPTY_FORM);
    setTestResult({ outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "" });
  };

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Settings</h1>
        <p className="text-gray-400 mt-1">Manage your Telnyx SIP Trunk configuration</p>
      </div>

      {user && (
        <div className="flex items-center gap-3 rounded-lg border border-gray-800 bg-gray-900 px-4 py-3">
          <div className="w-9 h-9 rounded-full bg-blue-600/20 flex items-center justify-center text-blue-300 font-semibold">
            {(user.name || user.email || "?").charAt(0).toUpperCase()}
          </div>
          <div className="min-w-0">
            <p className="text-sm text-white truncate">
              Signed in as <span className="font-semibold">{user.name || user.email}</span>
            </p>
            <p className="text-xs text-gray-500 truncate">
              {user.email}{user.email ? " · " : ""}
              <span className="uppercase tracking-wide text-gray-400">{user.role}</span>
            </p>
          </div>
          <span className="ml-auto flex items-center gap-1 text-xs text-green-400">
            <span className="w-2 h-2 rounded-full bg-green-400" /> Active
          </span>
        </div>
      )}

      {!isAdmin ? (
        <Card className="bg-gray-900 border-gray-800">
          <CardContent className="py-10 text-center text-gray-500">
            <Radio className="w-8 h-8 mx-auto mb-2 opacity-40" />
            <p className="text-sm">Admin access required to manage SIP trunk settings.</p>
          </CardContent>
        </Card>
      ) : (
        <Card className="bg-gray-900 border-gray-800">
          <CardHeader className="flex flex-row items-center justify-between">
            <CardTitle className="text-white text-base flex items-center gap-2">
              <Radio className="w-5 h-5 text-green-400" />
              Telnyx SIP Trunk
              {telnyxQuery.data?.enabled && telnyxQuery.data?.connectionId && (
                <span className="ml-2 px-2 py-0.5 rounded text-xs font-semibold bg-green-500/10 text-green-400 border border-green-500/20">
                  Connected
                </span>
              )}
            </CardTitle>
            {!showForm && (
              <Button
                size="sm"
                className="bg-blue-600 hover:bg-blue-700"
                onClick={() => {
                  setShowForm(true);
                  setEditingId(null);
                  setForm(EMPTY_FORM);
                  setSaveStatus({ type: "idle", message: "" });
                  setTestResult({ outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "" });
                }}
              >
                <Plus className="w-4 h-4 mr-1" /> Add Phone Number
              </Button>
            )}
          </CardHeader>

          <CardContent className="space-y-4">

            {/* ── Saved credentials list ── */}
            {!showForm && (
              <>
                {numbersQuery.isLoading || telnyxQuery.isLoading ? (
                  <div className="flex items-center justify-center py-8 text-gray-500">
                    <Loader2 className="w-5 h-5 animate-spin mr-2" /> Loading…
                  </div>
                ) : phoneNumbers.length === 0 ? (
                  <div className="text-center py-10 text-gray-500">
                    <Phone className="w-9 h-9 mx-auto mb-2 opacity-30" />
                    <p className="text-sm">No phone credentials yet.</p>
                    <p className="text-xs mt-1">Click "Add Phone Number" to configure your first SIP trunk line.</p>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {phoneNumbers.map((n) => (
                      <div
                        key={n.id}
                        className="flex items-center gap-3 px-4 py-3 rounded-lg border border-gray-800 bg-gray-800/30"
                      >
                        <div className="w-8 h-8 rounded-full bg-blue-600/20 flex items-center justify-center shrink-0">
                          <Phone className="w-4 h-4 text-blue-400" />
                        </div>

                        <div className="flex-1 min-w-0">
                          <p className="text-white font-medium">{n.number}</p>
                          {n.label && (
                            <p className="text-xs text-gray-400 mt-0.5">{n.label}</p>
                          )}
                        </div>

                        <span className={`text-xs px-2 py-0.5 rounded font-medium shrink-0 ${
                          n.status === "active"
                            ? "bg-green-500/10 text-green-400"
                            : "bg-gray-700 text-gray-500"
                        }`}>
                          {n.status === "active" ? "Active" : "Inactive"}
                        </span>

                        <Button
                          variant="ghost" size="sm"
                          onClick={() => openEdit(n.id)}
                          className="h-8 w-8 p-0 text-gray-400 hover:text-white shrink-0"
                          title="Edit"
                        >
                          <Edit className="w-4 h-4" />
                        </Button>

                        {/* Don't show delete for synthetic entry — it lives in the Telnyx config */}
                        {!n.synthetic && (
                          <Button
                            variant="ghost" size="sm"
                            onClick={() => removePhoneMutation.mutate({ id: n.id })}
                            disabled={removePhoneMutation.isPending}
                            className="h-8 w-8 p-0 text-gray-400 hover:text-red-400 shrink-0"
                            title="Remove"
                          >
                            <Trash2 className="w-4 h-4" />
                          </Button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </>
            )}

            {/* ── Add / Edit form ── */}
            {showForm && (
              <div className="space-y-5 border border-gray-700 rounded-xl p-5 bg-gray-800/20">
                <div className="flex items-center justify-between">
                  <p className="text-sm font-semibold text-white">
                    {editingId === null ? "New Phone Credential"
                      : editingId === 0 ? "Edit Phone Credential"
                      : "Edit Phone Credential"}
                  </p>
                  <Button variant="ghost" size="sm" onClick={closeForm} className="h-7 w-7 p-0 text-gray-400 hover:text-white">
                    <X className="w-4 h-4" />
                  </Button>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {/* Phone number — read-only when editing a real entry */}
                  <div>
                    <Label className="text-gray-300 text-sm">
                      Phone Number <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      value={form.phoneNumber}
                      onChange={(e) => setForm({ ...form, phoneNumber: e.target.value })}
                      placeholder="+15550001111"
                      disabled={editingId !== null && editingId > 0}
                      className="bg-gray-800 border-gray-700 text-white mt-1 disabled:opacity-60"
                    />
                    <p className="text-xs text-gray-500 mt-1">E.164 format — e.g. +15550001111</p>
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">
                      SIP Username <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      value={form.sipUsername}
                      onChange={(e) => setForm({ ...form, sipUsername: e.target.value })}
                      placeholder="e.g. salesvora_agent"
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    <p className="text-xs text-gray-500 mt-1">From your Telnyx Credential Connection</p>
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">
                      SIP Password <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      type="password"
                      value={form.sipPassword}
                      onChange={(e) => setForm({ ...form, sipPassword: e.target.value })}
                      placeholder={
                        editingId !== null && telnyxQuery.data?.hasSipPassword
                          ? "saved — type to change"
                          : "SIP credential password"
                      }
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    {editingId !== null && telnyxQuery.data?.hasSipPassword && (
                      <p className="text-xs text-green-400 mt-1">Password saved. Leave blank to keep it.</p>
                    )}
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">
                      Telnyx API Key <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      type="password"
                      value={form.apiKey}
                      onChange={(e) => setForm({ ...form, apiKey: e.target.value })}
                      placeholder={
                        telnyxQuery.data?.hasApiKey
                          ? `Saved: ${telnyxQuery.data.apiKeyPreview}`
                          : "KEYxxxxxxxxxxxxxxxxxxxxxxxx"
                      }
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    {telnyxQuery.data?.hasApiKey && (
                      <p className="text-xs text-green-400 mt-1">API key saved. Leave blank to keep it.</p>
                    )}
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">SIP Host</Label>
                    <Input
                      value={form.sipHost}
                      onChange={(e) => setForm({ ...form, sipHost: e.target.value })}
                      placeholder="yourname.sip.telnyx.com"
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">Connection ID</Label>
                    <Input
                      value={form.connectionId}
                      onChange={(e) => setForm({ ...form, connectionId: e.target.value })}
                      placeholder="e.g. 2985974513046390685"
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    <p className="text-xs text-gray-500 mt-1">From Telnyx → Voice → SIP Connections</p>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <div>
                    <Label className="text-gray-300 text-sm">Enable for outbound calls</Label>
                    <p className="text-xs text-gray-500">Routes real calls through this SIP connection</p>
                  </div>
                  <Switch
                    checked={form.enabled}
                    onCheckedChange={(v) => setForm({ ...form, enabled: v })}
                  />
                </div>

                {/* Test section — only shown when all required fields are filled */}
                {isFormComplete && (
                  <div className="border-t border-gray-700 pt-5 space-y-3">
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="text-sm font-semibold text-white">Test Phone Number</p>
                        <p className="text-xs text-gray-500 mt-0.5">
                          Verify outgoing and incoming connectivity before saving
                        </p>
                      </div>
                      <Button
                        onClick={handleTest}
                        disabled={testTelnyxMutation.isPending}
                        className="bg-green-600 hover:bg-green-700 shrink-0"
                        size="sm"
                      >
                        {testTelnyxMutation.isPending ? (
                          <><Loader2 className="w-4 h-4 mr-1 animate-spin" /> Testing…</>
                        ) : "Test Connection"}
                      </Button>
                    </div>

                    {(testResult.outgoing !== "idle" || testResult.incoming !== "idle") && (
                      <div className="space-y-2">
                        <TestResultRow state={testResult.outgoing} label="Outgoing Call"
                          message={testResult.outgoingMessage}
                          icon={<PhoneCall className="w-4 h-4 shrink-0" />} />
                        <TestResultRow state={testResult.incoming} label="Incoming Call"
                          message={testResult.incomingMessage}
                          icon={<PhoneIncoming className="w-4 h-4 shrink-0" />} />
                      </div>
                    )}
                  </div>
                )}

                {saveStatus.type !== "idle" && (
                  <div className={`text-sm rounded-md px-3 py-2 border ${
                    saveStatus.type === "ok"
                      ? "bg-green-500/10 text-green-400 border-green-500/20"
                      : "bg-red-500/10 text-red-400 border-red-500/20"
                  }`}>
                    {saveStatus.message}
                  </div>
                )}

                <div className="flex gap-2 pt-1">
                  <Button
                    onClick={handleSave}
                    disabled={
                      saveTelnyxMutation.isPending ||
                      addPhoneMutation.isPending ||
                      updatePhoneNumberMutation.isPending
                    }
                    className="bg-blue-600 hover:bg-blue-700"
                  >
                    <Save className="w-4 h-4 mr-1" />
                    {saveTelnyxMutation.isPending || addPhoneMutation.isPending || updatePhoneNumberMutation.isPending
                      ? "Saving…"
                      : "Save Credential"}
                  </Button>
                  <Button variant="outline" onClick={closeForm} className="border-gray-700 text-gray-300 hover:text-white">
                    Cancel
                  </Button>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

function TestResultRow({
  state, label, message, icon,
}: {
  state: TestState; label: string; message: string; icon: JSX.Element;
}) {
  const colorClass =
    state === "ok"    ? "bg-green-500/10 border-green-500/20 text-green-400" :
    state === "error" ? "bg-red-500/10 border-red-500/20 text-red-400" :
                        "bg-gray-800 border-gray-700 text-gray-300";
  return (
    <div className={`flex items-start gap-3 px-3 py-2.5 rounded-md border text-sm ${colorClass}`}>
      <span className="mt-0.5">{icon}</span>
      <span className="mt-0.5">
        {state === "loading" && <Loader2 className="w-4 h-4 animate-spin" />}
        {state === "ok"      && <CheckCircle className="w-4 h-4" />}
        {state === "error"   && <XCircle className="w-4 h-4" />}
      </span>
      <div>
        <p className="font-medium">{label}</p>
        <p className="text-xs opacity-80 mt-0.5">{message}</p>
      </div>
    </div>
  );
}

