import { useState, useRef, useCallback, useEffect } from "react";

export type RecorderStatus = "inactive" | "recording" | "paused" | "stopped";

interface UseCallRecorderResult {
  status: RecorderStatus;
  isRecording: boolean;
  recordingTime: number; // seconds
  audioUrl: string | null; // object URL for playback
  audioDataUrl: string | null; // base64 data URL for persistence
  audioBlob: Blob | null;
  error: string | null;
  startRecording: (getRemoteStream?: () => MediaStream | null) => Promise<void>;
  pauseRecording: () => void;
  resumeRecording: () => void;
  stopRecording: () => Promise<{ dataUrl: string; blob: Blob; duration: number } | null>;
  resetRecording: () => void;
  setMicMuted: (muted: boolean) => void;
}

/**
 * Browser microphone call recorder built on the MediaRecorder API.
 * - start / pause / resume / stop
 * - live elapsed-time counter
 * - produces both an object URL (instant playback) and a base64
 *   data URL (safe to persist via tRPC -> db)
 */
export function useCallRecorder(): UseCallRecorderResult {
  const [status, setStatus] = useState<RecorderStatus>("inactive");
  const [recordingTime, setRecordingTime] = useState(0);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [audioDataUrl, setAudioDataUrl] = useState<string | null>(null);
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const remotePollRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const objectUrlRef = useRef<string | null>(null);
  const stopResolverRef = useRef<((v: { dataUrl: string; blob: Blob; duration: number } | null) => void) | null>(null);
  const timeRef = useRef(0);

  const clearTimer = () => {
    if (timerRef.current) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }
  };

  const startTimer = () => {
    clearTimer();
    timerRef.current = setInterval(() => {
      timeRef.current += 1;
      setRecordingTime(timeRef.current);
    }, 1000);
  };

  const releaseStream = () => {
    if (remotePollRef.current) {
      clearInterval(remotePollRef.current);
      remotePollRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((t) => t.stop());
      streamRef.current = null;
    }
    if (audioCtxRef.current) {
      try {
        audioCtxRef.current.close();
      } catch {
        /* noop */
      }
      audioCtxRef.current = null;
    }
  };

  const pickMimeType = (): string => {
    const candidates = ["audio/webm;codecs=opus", "audio/webm", "audio/mp4", "audio/ogg;codecs=opus"];
    for (const c of candidates) {
      if (typeof MediaRecorder !== "undefined" && MediaRecorder.isTypeSupported(c)) return c;
    }
    return "";
  };

  const startRecording = useCallback(async (getRemoteStream?: () => MediaStream | null) => {
    setError(null);
    if (typeof navigator === "undefined" || !navigator.mediaDevices?.getUserMedia) {
      setError("Recording is not supported in this browser.");
      return;
    }
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== "inactive") {
      return; // already recording
    }
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: { echoCancellation: true, noiseSuppression: true },
      });
      streamRef.current = stream;
      chunksRef.current = [];

      // Record through a Web Audio mixer so we can blend the agent's mic with
      // the client's call audio into ONE recording (both sides of the call).
      let recordStream: MediaStream = stream;
      if (getRemoteStream) {
        try {
          const Ctx: typeof AudioContext =
            window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
          const ctx = new Ctx();
          audioCtxRef.current = ctx;
          if (ctx.state === "suspended") await ctx.resume();
          const dest = ctx.createMediaStreamDestination();
          ctx.createMediaStreamSource(stream).connect(dest); // agent mic
          recordStream = dest.stream;

          // The client's audio stream may attach a moment after the call
          // connects, so keep trying to add it until it's available.
          let remoteAttached = false;
          const attachRemote = () => {
            if (remoteAttached || !audioCtxRef.current) return;
            const rs = getRemoteStream();
            if (rs && rs.getAudioTracks().length > 0) {
              try {
                audioCtxRef.current.createMediaStreamSource(rs).connect(dest); // client audio
                remoteAttached = true;
                if (remotePollRef.current) {
                  clearInterval(remotePollRef.current);
                  remotePollRef.current = null;
                }
              } catch {
                /* will retry */
              }
            }
          };
          attachRemote();
          if (!remoteAttached) {
            remotePollRef.current = setInterval(attachRemote, 400);
            // give up trying after ~12s
            setTimeout(() => {
              if (remotePollRef.current) {
                clearInterval(remotePollRef.current);
                remotePollRef.current = null;
              }
            }, 12000);
          }
        } catch {
          recordStream = stream; // mixing unavailable -> mic only
        }
      }

      const mimeType = pickMimeType();
      const recorder = mimeType ? new MediaRecorder(recordStream, { mimeType }) : new MediaRecorder(recordStream);
      mediaRecorderRef.current = recorder;

      recorder.ondataavailable = (e: BlobEvent) => {
        if (e.data && e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onerror = () => {
        setError("Recording failed unexpectedly.");
        setStatus("inactive");
        clearTimer();
        releaseStream();
      };

      recorder.onstop = () => {
        clearTimer();
        const type = recorder.mimeType || "audio/webm";
        const blob = new Blob(chunksRef.current, { type });
        const finalDuration = timeRef.current;

        // Revoke any previous object URL
        if (objectUrlRef.current) URL.revokeObjectURL(objectUrlRef.current);
        const url = URL.createObjectURL(blob);
        objectUrlRef.current = url;

        setAudioBlob(blob);
        setAudioUrl(url);
        setStatus("stopped");
        releaseStream();

        // Convert to base64 data URL for persistence
        const reader = new FileReader();
        reader.onloadend = () => {
          const dataUrl = typeof reader.result === "string" ? reader.result : "";
          setAudioDataUrl(dataUrl);
          if (stopResolverRef.current) {
            stopResolverRef.current(dataUrl ? { dataUrl, blob, duration: finalDuration } : null);
            stopResolverRef.current = null;
          }
        };
        reader.onerror = () => {
          if (stopResolverRef.current) {
            stopResolverRef.current(null);
            stopResolverRef.current = null;
          }
        };
        reader.readAsDataURL(blob);
      };

      recorder.start(1000); // collect data every second
      timeRef.current = 0;
      setRecordingTime(0);
      setStatus("recording");
      startTimer();
    } catch (err) {
      const e = err as { name?: string; message?: string };
      if (e?.name === "NotAllowedError" || e?.name === "PermissionDeniedError") {
        setError("Microphone permission denied. Please allow microphone access to record calls.");
      } else if (e?.name === "NotFoundError") {
        setError("No microphone found on this device.");
      } else {
        setError("Could not start recording: " + (e?.message || "unknown error"));
      }
      setStatus("inactive");
      releaseStream();
    }
  }, []);

  const pauseRecording = useCallback(() => {
    const rec = mediaRecorderRef.current;
    if (rec && rec.state === "recording") {
      rec.pause();
      clearTimer();
      setStatus("paused");
    }
  }, []);

  const resumeRecording = useCallback(() => {
    const rec = mediaRecorderRef.current;
    if (rec && rec.state === "paused") {
      rec.resume();
      startTimer();
      setStatus("recording");
    }
  }, []);

  /**
   * Stops recording and resolves with { dataUrl, blob, duration } once the
   * audio has been finalized — safe to await before saving to the backend.
   */
  const stopRecording = useCallback((): Promise<{ dataUrl: string; blob: Blob; duration: number } | null> => {
    const rec = mediaRecorderRef.current;
    if (!rec || rec.state === "inactive") {
      return Promise.resolve(null);
    }
    return new Promise((resolve) => {
      stopResolverRef.current = resolve;
      try {
        rec.stop();
      } catch {
        stopResolverRef.current = null;
        resolve(null);
      }
    });
  }, []);

  const resetRecording = useCallback(() => {
    const rec = mediaRecorderRef.current;
    if (rec && rec.state !== "inactive") {
      try {
        rec.stop();
      } catch {
        /* noop */
      }
    }
    clearTimer();
    releaseStream();
    if (objectUrlRef.current) {
      URL.revokeObjectURL(objectUrlRef.current);
      objectUrlRef.current = null;
    }
    chunksRef.current = [];
    timeRef.current = 0;
    mediaRecorderRef.current = null;
    setStatus("inactive");
    setRecordingTime(0);
    setAudioUrl(null);
    setAudioDataUrl(null);
    setAudioBlob(null);
    setError(null);
  }, []);

  /** Mute/unmute the microphone track without stopping the recording. */
  const setMicMuted = useCallback((muted: boolean) => {
    if (streamRef.current) {
      streamRef.current.getAudioTracks().forEach((t) => (t.enabled = !muted));
    }
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      clearTimer();
      const rec = mediaRecorderRef.current;
      if (rec && rec.state !== "inactive") {
        try {
          rec.stop();
        } catch {
          /* noop */
        }
      }
      releaseStream();
      if (objectUrlRef.current) URL.revokeObjectURL(objectUrlRef.current);
    };
  }, []);

  return {
    status,
    isRecording: status === "recording" || status === "paused",
    recordingTime,
    audioUrl,
    audioDataUrl,
    audioBlob,
    error,
    startRecording,
    pauseRecording,
    resumeRecording,
    stopRecording,
    resetRecording,
    setMicMuted,
  };
}

import { useCallback, useEffect, useRef, useState } from "react";

export type RtcStatus = "off" | "connecting" | "registered" | "error";
export type RtcCallState = "idle" | "ringing" | "active" | "ended";

type Options = { enabled: boolean; login: string; password: string };

// Lazily loaded Telnyx WebRTC client. We use `any` for the SDK objects because
// the SDK is dynamically imported (browser-only) and not part of our types.
type AnyClient = {
  on: (ev: string, cb: (p: unknown) => void) => void;
  connect: () => void;
  disconnect: () => void;
  newCall: (opts: Record<string, unknown>) => AnyCall;
};
type AnyCall = {
  hangup: () => void;
  answer: () => void;
  dtmf?: (digit: string) => void;
  muteAudio: () => void;
  unmuteAudio: () => void;
  state?: string;
  direction?: "inbound" | "outbound";
  cause?: string;
  causeCode?: number;
  sipReason?: string;
  sipCode?: number;
  remoteCallerNumber?: string;
  remoteCallerName?: string;
  remoteStream?: MediaStream;
  localStream?: MediaStream;
};

const REMOTE_AUDIO_ID = "telnyx-remote-audio";

// Telnyx sends errors as objects, strings, or Errors. Pull out something useful.
function describeError(e: unknown): string {
  if (!e) return "Unknown WebRTC error.";
  if (typeof e === "string") return e;
  if (e instanceof Error) return e.message;
  const o = e as Record<string, any>;
  const parts = [
    o.message,
    o.error?.message,
    o.error?.cause,
    o.cause,
    o.reason,
    o.code != null ? `code ${o.code}` : undefined,
    o.error?.code != null ? `code ${o.error.code}` : undefined,
  ].filter(Boolean);
  if (parts.length) return String(parts.join(" — "));
  try {
    return JSON.stringify(o);
  } catch {
    return "WebRTC error.";
  }
}

export function useTelnyxRTC({ enabled, login, password }: Options) {
  const [status, setStatus] = useState<RtcStatus>("off");
  const [callState, setCallState] = useState<RtcCallState>("idle");
  const [callDirection, setCallDirection] = useState<"inbound" | "outbound" | null>(null);
  const [incomingCallerNumber, setIncomingCallerNumber] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const clientRef = useRef<AnyClient | null>(null);
  const callRef = useRef<AnyCall | null>(null);

  // Connect / disconnect when credentials become available.
  useEffect(() => {
    let cancelled = false;
    if (!enabled || !login || !password) {
      setStatus("off");
      return;
    }
    setStatus("connecting");
    setError(null);

    (async () => {
      try {
        const mod = await import("@telnyx/webrtc");
        if (cancelled) return;
        const TelnyxRTC = (mod as { TelnyxRTC: new (o: Record<string, unknown>) => AnyClient }).TelnyxRTC;
        const client = new TelnyxRTC({
          login,
          password,
          // Relay media through Telnyx TURN to traverse firewalls/NAT.
          forceRelayCandidate: true,
          prefetchIceCandidates: true,
        });

        let reconnects = 0;

        client.on("telnyx.ready", () => !cancelled && setStatus("registered"));
        client.on("telnyx.error", (e: unknown) => {
          if (cancelled) return;
          console.error("[Telnyx] error:", e);
          setStatus("error");
          setError(describeError(e));
        });
        client.on("telnyx.socket.error", (e: unknown) => {
          if (cancelled) return;
          console.error("[Telnyx] socket error:", e);
          setStatus("error");
          setError(describeError(e) || "Could not reach Telnyx (socket error).");
        });
        client.on("telnyx.socket.close", () => {
          if (cancelled) return;
          reconnects += 1;
          setStatus((s) => (s === "registered" ? "connecting" : s));
          // Repeated drops = unhealthy signaling path (often a VPN/proxy or
          // restrictive network). Tell the user something actionable.
          if (reconnects >= 2) {
            setError(
              "Connection to Telnyx keeps dropping (signaling timed out). This is a network issue — disable any VPN/proxy, avoid restrictive Wi-Fi, and try again.",
            );
          }
        });
        client.on("telnyx.notification", (n: unknown) => {
          if (cancelled) return;
          const note = n as { type?: string; call?: AnyCall; error?: unknown };
          if (note?.type === "userMediaError") {
            setError("Microphone access failed. Allow mic permission and use http://localhost or https.");
            return;
          }
          if (note?.type === "callUpdate" && note.call) {
            callRef.current = note.call;
            const s = String(note.call.state || "");
            if (["new", "requesting", "trying", "ringing", "early"].includes(s)) {
              const dir = note.call.direction === "inbound" ? "inbound" : "outbound";
              setCallDirection(dir);
              if (dir === "inbound") {
                setIncomingCallerNumber(note.call.remoteCallerNumber || note.call.remoteCallerName || "Unknown");
              }
              setCallState("ringing");
            } else if (s === "active") {
              setCallState("active");
            } else if (["hangup", "destroy", "purge"].includes(s)) {
              const c = note.call;
              const failed = c.sipCode && c.sipCode >= 400;
              if (failed || (c.cause && c.cause !== "NORMAL_CLEARING" && c.cause !== "USER_HANGUP")) {
                setError(`Call ended: ${c.sipReason || c.cause || "failed"}${c.sipCode ? ` (SIP ${c.sipCode})` : ""}`);
              }
              setCallState("ended");
              setCallDirection(null);
              setIncomingCallerNumber(null);
              callRef.current = null;
            }
          }
        });

        client.connect();
        clientRef.current = client;
      } catch (e) {
        if (!cancelled) {
          setStatus("error");
          setError(e instanceof Error ? e.message : "Failed to load the WebRTC client.");
        }
      }
    })();

    return () => {
      cancelled = true;
      try {
        callRef.current?.hangup();
      } catch { /* noop */ }
      try {
        clientRef.current?.disconnect();
      } catch { /* noop */ }
      clientRef.current = null;
      callRef.current = null;
    };
  }, [enabled, login, password]);

  const makeCall = useCallback((destinationNumber: string, callerNumber: string) => {
    setError(null);
    if (!clientRef.current || status !== "registered") {
      setError("Browser calling isn't connected yet. Check your SIP credentials in Settings.");
      return false;
    }
    try {
      callRef.current = clientRef.current.newCall({
        destinationNumber,
        callerNumber,
        audio: true,
        video: false,
        remoteElement: REMOTE_AUDIO_ID,
      });
      setCallState("ringing");
      return true;
    } catch (e) {
      setError(e instanceof Error ? e.message : "Could not start the call.");
      return false;
    }
  }, [status]);

  const sendDTMF = useCallback((digit: string) => {
    try { callRef.current?.dtmf?.(digit); } catch { /* noop */ }
  }, []);

  const answerCall = useCallback(() => {
    try {
      callRef.current?.answer();
    } catch { /* noop */ }
    setCallState("active");
  }, []);

  const hangup = useCallback(() => {
    try {
      callRef.current?.hangup();
    } catch { /* noop */ }
    callRef.current = null;
    setCallDirection(null);
    setIncomingCallerNumber(null);
    setCallState("idle");
  }, []);

  const setMuted = useCallback((muted: boolean) => {
    try {
      if (muted) callRef.current?.muteAudio();
      else callRef.current?.unmuteAudio();
    } catch { /* noop */ }
  }, []);

  // The client's audio. Prefer the live call's remoteStream; fall back to the
  // remote <audio> element's srcObject. Used by the recorder to mix both sides.
  const getRemoteStream = useCallback((): MediaStream | null => {
    const fromCall = callRef.current?.remoteStream;
    if (fromCall instanceof MediaStream && fromCall.getAudioTracks().length) return fromCall;
    if (typeof document === "undefined") return null;
    const el = document.getElementById(REMOTE_AUDIO_ID) as HTMLAudioElement | null;
    const src = el?.srcObject;
    return src instanceof MediaStream ? src : null;
  }, []);

  return {
    status,
    callState,
    callDirection,
    incomingCallerNumber,
    error,
    makeCall,
    answerCall,
    sendDTMF,
    hangup,
    setMuted,
    getRemoteStream,
    remoteAudioId: REMOTE_AUDIO_ID,
  };
}

