import { useState, useEffect, useRef } from "react";
import { trpc } from "@/providers/trpc";
import { useAuth } from "@/hooks/useAuth";
import { useCallRecorder } from "@/hooks/useCallRecorder";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import {
} from "@/components/ui/select";
import {
  Radio,
  Play,
  Pause,
  SkipForward,
  PhoneOff,
  Clock,
  List,
  Phone,
  CheckCircle2,
  XCircle,
  Ban,
  User,
  Building,
  Briefcase,
  MapPin,
  Mail,
  BarChart3,
  Disc,
  Square,
  Download,
  Mic,
  MicOff,
  Pencil,
  Check,
  X,
} from "lucide-react";

export default function AutoDialerPage() {
  const { user } = useAuth();
  const companyId = user?.companyId || 1;

  const [selectedCampaignId, setSelectedCampaignId] = useState<string>("");
  const [isRunning, setIsRunning] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [callStatus, setCallStatus] = useState<"idle" | "calling" | "connected" | "disposition">("idle");
  const [duration, setDuration] = useState(0);
  const [callNotes, setCallNotes] = useState("");
  const [, setSelectedDisposition] = useState<string | null>(null);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Active call ID and Campaign Lead ID
  const [activeCallId, setActiveCallId] = useState<number | null>(null);

  // ── Editable Client Details (live during call) ──
  const [isEditingLead, setIsEditingLead] = useState(false);
  const [leadEdit, setLeadEdit] = useState<Record<string, string>>({});
  const [leadSaveMsg, setLeadSaveMsg] = useState<string | null>(null);

  // ── Call Recording ──
  const recorder = useCallRecorder();
  const [isMuted, setIsMuted] = useState(false);
  const [savedRecordingDataUrl, setSavedRecordingDataUrl] = useState<string | null>(null);
  const [recordingDuration, setRecordingDuration] = useState(0);

  // Queries
  const { data: campaigns = [], refetch: refetchCampaigns } = trpc.campaign.list.useQuery();
  const { data: dispositions = [] } = trpc.calls.dispositions.useQuery({ companyId });

  // Get campaign progress metrics
  const campIdVal = parseInt(selectedCampaignId) || 0;
  const { data: campaignProgress, refetch: refetchProgress } = trpc.campaign.progress.useQuery(
    { id: campIdVal },
    { enabled: !!selectedCampaignId }
  );

  // Get next lead in the campaign
  const { data: nextCampaignLead, refetch: refetchNextLead } = trpc.campaign.getNextLead.useQuery(
    { campaignId: campIdVal },
    { enabled: isRunning && !isPaused && callStatus === "idle" }
  );

  // Synchronize state when campaigns load
  useEffect(() => {
    const autoCamps = campaigns.filter((c: any) => c.type === "auto");
    if (autoCamps.length > 0 && !selectedCampaignId) {
      setSelectedCampaignId(autoCamps[0].id.toString());
    }
  }, [campaigns, selectedCampaignId]);

  // Call timer
  useEffect(() => {
    if (callStatus === "connected" && !isPaused) {
      timerRef.current = setInterval(() => setDuration((d) => d + 1), 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [callStatus, isPaused]);

  // Automated dial cycle hook
  useEffect(() => {
    if (isRunning && !isPaused && callStatus === "idle" && nextCampaignLead) {
      // Initiate call to next lead
      triggerAutoDialCall();
    }
  }, [isRunning, isPaused, callStatus, nextCampaignLead]);

  // Keep recorder mic in sync with the Mute button
  useEffect(() => {
    recorder.setMicMuted(isMuted);
  }, [isMuted, recorder]);

  // Mutations
  const startCampaignMutation = trpc.campaign.start.useMutation();
  const pauseCampaignMutation = trpc.campaign.pause.useMutation();
  const initiateCallMutation = trpc.calls.initiate.useMutation();
  const updateStatusMutation = trpc.calls.updateStatus.useMutation();
  const updateLeadStatusMutation = trpc.campaign.updateLeadStatus.useMutation();
  const endCallMutation = trpc.calls.endCall.useMutation();
  const saveRecordingMutation = trpc.calls.saveRecording.useMutation();
  const updateLeadMutation = trpc.lead.update.useMutation();

  const startEditLead = () => {
    if (!currentLead) return;
    setLeadEdit({
      firstName: currentLead.firstName || "",
      lastName: currentLead.lastName || "",
      phone: currentLead.phone || "",
      email: currentLead.email || "",
      companyName: currentLead.companyName || "",
      designation: currentLead.designation || "",
      city: currentLead.city || "",
      notes: currentLead.notes || "",
    });
    setIsEditingLead(true);
    setLeadSaveMsg(null);
  };

  const cancelEditLead = () => {
    setIsEditingLead(false);
    setLeadEdit({});
  };

  const saveEditLead = async () => {
    if (!currentLead) return;
    try {
      await updateLeadMutation.mutateAsync({
        id: currentLead.id,
        data: {
          firstName: leadEdit.firstName || undefined,
          lastName: leadEdit.lastName || undefined,
          phone: leadEdit.phone || undefined,
          email: leadEdit.email || undefined,
          companyName: leadEdit.companyName || undefined,
          designation: leadEdit.designation || undefined,
          city: leadEdit.city || undefined,
          notes: leadEdit.notes || undefined,
        },
      });
      setLeadSaveMsg("Client details updated ✓");
      setIsEditingLead(false);
      refetchNextLead();
      setTimeout(() => setLeadSaveMsg(null), 3000);
    } catch (err) {
      console.error("Failed to update lead:", err);
      setLeadSaveMsg("Failed to save changes");
    }
  };

  const handleToggleRecording = async () => {
    if (recorder.status === "recording" || recorder.status === "paused") {
      const result = await recorder.stopRecording();
      if (result) {
        setSavedRecordingDataUrl(result.dataUrl);
        setRecordingDuration(result.duration);
      }
    } else {
      await recorder.startRecording();
    }
  };

  const finalizeRecording = async (): Promise<{ dataUrl: string; duration: number } | null> => {
    if (recorder.status === "recording" || recorder.status === "paused") {
      const result = await recorder.stopRecording();
      if (result) {
        setSavedRecordingDataUrl(result.dataUrl);
        setRecordingDuration(result.duration);
        return { dataUrl: result.dataUrl, duration: result.duration };
      }
      return null;
    }
    if (savedRecordingDataUrl) {
      return { dataUrl: savedRecordingDataUrl, duration: recordingDuration };
    }
    return null;
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`;
  };

  const startDialer = async () => {
    if (!selectedCampaignId) return;
    setIsRunning(true);
    setIsPaused(false);
    setCallStatus("idle");
    try {
      await startCampaignMutation.mutateAsync({ id: campIdVal });
      refetchCampaigns();
      refetchProgress();
      refetchNextLead();
    } catch (err) {
      console.error("Failed to start auto-dialer campaign:", err);
    }
  };

  const triggerAutoDialCall = async () => {
    if (!nextCampaignLead?.lead) return;
    setCallStatus("calling");
    try {
      const activeCall = await initiateCallMutation.mutateAsync({
        leadId: nextCampaignLead.lead.id,
        campaignId: campIdVal,
        companyId,
        toNumber: nextCampaignLead.lead.phone,
        type: "auto",
      });
      setActiveCallId(activeCall.id);

      await updateLeadStatusMutation.mutateAsync({
        campaignLeadId: nextCampaignLead.id,
        status: "in_progress",
        callerId: user?.id,
      });

      // Simulate connection
      setTimeout(async () => {
        setCallStatus("connected");
        setDuration(0);
        await updateStatusMutation.mutateAsync({
          id: activeCall.id,
          status: "connected",
        });
      }, 2000);
    } catch (err) {
      console.error("Failed to execute autodial call:", err);
      setCallStatus("idle");
    }
  };

  const pauseDialer = async () => {
    setIsPaused(true);
    try {
      await pauseCampaignMutation.mutateAsync({ id: campIdVal });
      refetchCampaigns();
    } catch (err) {
      console.error("Failed to pause campaign:", err);
    }
  };

  const resumeDialer = async () => {
    setIsPaused(false);
    try {
      await startCampaignMutation.mutateAsync({ id: campIdVal });
      refetchCampaigns();
      refetchNextLead();
    } catch (err) {
      console.error("Failed to resume campaign:", err);
    }
  };

  const handleEndCall = async () => {
    setCallStatus("disposition");
    if (timerRef.current) clearInterval(timerRef.current);
    // Auto-stop and keep the recording when the call ends
    await finalizeRecording();
    if (activeCallId) {
      try {
        await updateStatusMutation.mutateAsync({
          id: activeCallId,
          status: "completed",
        });
      } catch (err) {
        console.error("Failed to update status on end call:", err);
      }
    }
  };

  const handleDisposition = async (dispId: string) => {
    setSelectedDisposition(dispId);
    if (activeCallId && nextCampaignLead) {
      try {
        // Map disposition category to lead status update
        const selectedDispObj = dispositions.find((d: any) => d.id.toString() === dispId);
        let leadStatus: "completed" | "failed" | "skipped" | "callback" = "completed";
        if (selectedDispObj) {
          if (selectedDispObj.category === "no_answer" || selectedDispObj.category === "wrong_number") {
            leadStatus = "failed";
          } else if (selectedDispObj.category === "callback") {
            leadStatus = "callback";
          }
        }

        const rec = await finalizeRecording();
        await endCallMutation.mutateAsync({
          id: activeCallId,
          dispositionId: parseInt(dispId),
          duration,
          notes: callNotes,
          callDescription: callNotes,
          recordingUrl: rec?.dataUrl || undefined,
        });
        if (rec?.dataUrl) {
          await saveRecordingMutation.mutateAsync({
            callId: activeCallId,
            recordingUrl: rec.dataUrl,
            duration: rec.duration,
            fileSize: recorder.audioBlob?.size,
            format: "webm",
          });
        }

        await updateLeadStatusMutation.mutateAsync({
          campaignLeadId: nextCampaignLead.id,
          status: leadStatus,
          callerId: user?.id,
        });
      } catch (err) {
        console.error("Failed to submit call disposition:", err);
      }
    }

    // Reset and query next lead
    setCallStatus("idle");
    setDuration(0);
    setCallNotes("");
    setSelectedDisposition(null);
    setActiveCallId(null);
    recorder.resetRecording();
    setSavedRecordingDataUrl(null);
    setRecordingDuration(0);
    setIsMuted(false);
    setIsEditingLead(false);
    setLeadEdit({});

    // Refresh campaign metrics and next lead
    refetchProgress();
    setTimeout(() => {
      refetchNextLead();
    }, 500);
  };

  const stopDialer = async () => {
    setIsRunning(false);
    setIsPaused(false);
    setCallStatus("idle");
    setDuration(0);
    if (timerRef.current) clearInterval(timerRef.current);
    recorder.resetRecording();
    setSavedRecordingDataUrl(null);
    setRecordingDuration(0);
    setIsMuted(false);
    try {
      await pauseCampaignMutation.mutateAsync({ id: campIdVal });
      refetchCampaigns();
    } catch (err) {
      console.error("Failed to stop campaign:", err);
    }
  };

  // Render disposition icon helper
  const getDispIcon = (category: string) => {
    switch (category) {
      case "connected":
      case "converted":
        return <CheckCircle2 className="w-4 h-4" />;
      case "no_answer":
        return <XCircle className="w-4 h-4" />;
      case "machine":
      case "voicemail":
        return <Radio className="w-4 h-4" />;
      default:
        return <Ban className="w-4 h-4" />;
    }
  };

  const progressTotal = campaignProgress?.total || 0;
  const progressCompleted = campaignProgress?.completed || 0;
  const progressPercentage = progressTotal > 0 ? Math.round((progressCompleted / progressTotal) * 100) : 0;
  const currentLead = nextCampaignLead?.lead || null;

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Auto Dialer</h1>
          <p className="text-gray-400 mt-1">Automated calling with sequential lead processing</p>
        </div>
        {!isRunning ? (
          <div className="flex gap-2">
            <select
              value={selectedCampaignId}
              onChange={(e) => setSelectedCampaignId(e.target.value)}
              className="bg-gray-900 border border-gray-800 rounded-md px-3 py-2 text-white text-sm"
            >
              <option value="">Select campaign...</option>
              {campaigns.filter((c: any) => c.type === "auto").map((c: any) => (
                <option key={c.id} value={c.id.toString()}>{c.name}</option>
              ))}
            </select>
            <Button 
              className="bg-green-600 hover:bg-green-700" 
              onClick={startDialer}
              disabled={!selectedCampaignId}
            >
              <Play className="w-4 h-4 mr-2" /> Start
            </Button>
          </div>
        ) : (
          <div className="flex gap-2">
            {isPaused ? (
              <Button className="bg-green-600 hover:bg-green-700" onClick={resumeDialer}>
                <Play className="w-4 h-4 mr-2" /> Resume
              </Button>
            ) : (
              <Button variant="outline" className="border-amber-600/30 text-amber-400 hover:bg-amber-600/20" onClick={pauseDialer}>
                <Pause className="w-4 h-4 mr-2" /> Pause
              </Button>
            )}
            <Button variant="outline" className="border-red-600/30 text-red-400 hover:bg-red-600/20" onClick={stopDialer}>
              <PhoneOff className="w-4 h-4 mr-2" /> Stop
            </Button>
          </div>
        )}
      </div>

      {/* Progress */}
      <Card className="bg-gray-900 border-gray-800">
        <CardContent className="p-4">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm text-gray-400">
              <List className="w-4 h-4 inline mr-1" />
              Progress: {progressCompleted.toLocaleString()} / {progressTotal.toLocaleString()} leads
            </span>
            <span className="text-sm font-medium text-white">{progressPercentage}%</span>
          </div>
          <Progress value={progressPercentage} className="h-3 bg-gray-800" />
        </CardContent>
      </Card>

      {isRunning && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Lead Info */}
          <Card className="bg-gray-900 border-gray-800">
            <CardContent className="p-5 space-y-4">
              <div className="flex items-center justify-between pb-3 border-b border-gray-800">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-blue-600/20 flex items-center justify-center">
                    <User className="w-5 h-5 text-blue-400" />
                  </div>
                  {currentLead ? (
                    <div>
                      <h3 className="text-base font-semibold text-white">{currentLead.firstName || ""} {currentLead.lastName || "Lead"}</h3>
                      <p className="text-xs text-gray-500">Lead ID: #{currentLead.id}</p>
                    </div>
                  ) : (
                    <div>
                      <h3 className="text-base font-semibold text-white">Searching...</h3>
                      <p className="text-xs text-gray-500">Finding next pending lead</p>
                    </div>
                  )}
                </div>
                <div className="flex items-center gap-2">
                  {currentLead && !isEditingLead && (
                    <Button
                      variant="outline"
                      size="sm"
                      title="Edit client details"
                      className="border-gray-700 text-gray-300 h-7 px-2"
                      onClick={startEditLead}
                    >
                      <Pencil className="w-3.5 h-3.5" />
                    </Button>
                  )}
                  <Badge className="bg-blue-500/20 text-blue-400">Current</Badge>
                </div>
              </div>
              {leadSaveMsg && (
                <p className={`text-xs text-center rounded-md py-1 ${leadSaveMsg.includes("Failed") ? "text-red-400 bg-red-500/10" : "text-green-400 bg-green-500/10"}`}>{leadSaveMsg}</p>
              )}
              {currentLead && isEditingLead ? (
                <div className="space-y-2">
                  <div className="grid grid-cols-2 gap-2">
                    <Input value={leadEdit.firstName} onChange={(e) => setLeadEdit({ ...leadEdit, firstName: e.target.value })} placeholder="First name" className="bg-gray-800 border-gray-700 text-white h-8 text-xs" />
                    <Input value={leadEdit.lastName} onChange={(e) => setLeadEdit({ ...leadEdit, lastName: e.target.value })} placeholder="Last name" className="bg-gray-800 border-gray-700 text-white h-8 text-xs" />
                  </div>
                  <Input value={leadEdit.phone} onChange={(e) => setLeadEdit({ ...leadEdit, phone: e.target.value })} placeholder="Phone" className="bg-gray-800 border-gray-700 text-white h-8 text-xs" />
                  <Input value={leadEdit.email} onChange={(e) => setLeadEdit({ ...leadEdit, email: e.target.value })} placeholder="Email" className="bg-gray-800 border-gray-700 text-white h-8 text-xs" />
                  <Input value={leadEdit.companyName} onChange={(e) => setLeadEdit({ ...leadEdit, companyName: e.target.value })} placeholder="Company" className="bg-gray-800 border-gray-700 text-white h-8 text-xs" />
                  <Input value={leadEdit.designation} onChange={(e) => setLeadEdit({ ...leadEdit, designation: e.target.value })} placeholder="Designation" className="bg-gray-800 border-gray-700 text-white h-8 text-xs" />
                  <Input value={leadEdit.city} onChange={(e) => setLeadEdit({ ...leadEdit, city: e.target.value })} placeholder="City" className="bg-gray-800 border-gray-700 text-white h-8 text-xs" />
                  <Textarea value={leadEdit.notes} onChange={(e) => setLeadEdit({ ...leadEdit, notes: e.target.value })} placeholder="Client record notes..." className="bg-gray-800 border-gray-700 text-white text-xs min-h-[50px]" />
                  <div className="flex gap-2 pt-1">
                    <Button size="sm" className="flex-1 bg-green-600 hover:bg-green-700 h-7" onClick={saveEditLead} disabled={updateLeadMutation.isPending}>
                      <Check className="w-3.5 h-3.5 mr-1" /> Save
                    </Button>
                    <Button size="sm" variant="outline" className="flex-1 border-gray-700 text-gray-300 h-7" onClick={cancelEditLead}>
                      <X className="w-3.5 h-3.5 mr-1" /> Cancel
                    </Button>
                  </div>
                </div>
              ) : currentLead ? (
                <div className="space-y-2 text-sm">
                  {currentLead.companyName && (
                    <div className="flex items-center gap-2 text-gray-300">
                      <Building className="w-4 h-4 text-gray-500" /> {currentLead.companyName}
                    </div>
                  )}
                  {currentLead.designation && (
                    <div className="flex items-center gap-2 text-gray-300">
                      <Briefcase className="w-4 h-4 text-gray-500" /> {currentLead.designation}
                    </div>
                  )}
                  <div className="flex items-center gap-2 text-gray-300">
                    <Phone className="w-4 h-4 text-gray-500" /> {currentLead.phone}
                  </div>
                  {currentLead.email && (
                    <div className="flex items-center gap-2 text-gray-300">
                      <Mail className="w-4 h-4 text-gray-500" /> {currentLead.email}
                    </div>
                  )}
                  {currentLead.city && (
                    <div className="flex items-center gap-2 text-gray-300">
                      <MapPin className="w-4 h-4 text-gray-500" /> {currentLead.city}
                    </div>
                  )}
                  {currentLead.customFields && Object.keys(currentLead.customFields).length > 0 && (
                    <div className="pt-2 border-t border-gray-800 space-y-1">
                      <p className="text-[10px] font-medium text-gray-500 uppercase">Custom Client Details</p>
                      {Object.entries(currentLead.customFields).map(([k, v]: [string, any]) => (
                        <div key={k} className="flex justify-between text-xs">
                          <span className="text-gray-500">{k}</span>
                          <span className="text-gray-300">{String(v)}</span>
                        </div>
                      ))}
                    </div>
                  )}
                  {currentLead.notes && (
                    <div className="pt-2 border-t border-gray-800">
                      <p className="text-[10px] font-medium text-gray-500 uppercase mb-0.5">Client Record Notes</p>
                      <p className="text-xs text-gray-400 italic">{currentLead.notes}</p>
                    </div>
                  )}
                </div>
              ) : (
                <div className="text-center py-4 text-gray-500 text-sm">
                  Waiting for next pending campaign lead...
                </div>
              )}
            </CardContent>
          </Card>

          {/* Call Interface */}
          <Card className="bg-gray-900 border-gray-800">
            <CardContent className="p-5">
              {callStatus === "calling" && (
                <div className="text-center py-8 space-y-4">
                  <div className="w-16 h-16 rounded-full bg-blue-500/20 flex items-center justify-center mx-auto animate-pulse">
                    <Phone className="w-8 h-8 text-blue-400" />
                  </div>
                  <div>
                    <p className="text-lg font-semibold text-white">Auto-dialing...</p>
                    <p className="text-gray-400">{currentLead?.phone}</p>
                  </div>
                </div>
              )}

              {callStatus === "connected" && (
                <div className="space-y-4">
                  <div className="text-center">
                    <div className="w-14 h-14 rounded-full bg-green-500/20 flex items-center justify-center mx-auto animate-pulse">
                      <Phone className="w-7 h-7 text-green-400" />
                    </div>
                    <p className="text-2xl font-bold text-white font-mono mt-2">{formatDuration(duration)}</p>
                    <Badge className="bg-green-500/20 text-green-400 mt-1">Connected</Badge>
                  </div>

                  {/* Recording indicator */}
                  {recorder.isRecording && (
                    <div className="flex items-center justify-center gap-2 bg-red-500/10 border border-red-500/30 rounded-lg py-1.5 px-3">
                      <span className="relative flex h-2.5 w-2.5">
                        <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75" />
                        <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-red-500" />
                      </span>
                      <span className="text-xs font-semibold text-red-400 tracking-wider">REC</span>
                      <span className="text-xs font-mono text-red-300">{formatDuration(recorder.recordingTime)}</span>
                    </div>
                  )}
                  {recorder.error && (
                    <p className="text-xs text-red-400 text-center bg-red-500/10 border border-red-500/30 rounded-md py-1.5 px-2">{recorder.error}</p>
                  )}

                  {/* Call controls: Mute + Record */}
                  <div className="flex justify-center gap-3">
                    <Button
                      variant="outline"
                      size="sm"
                      title={isMuted ? "Unmute" : "Mute"}
                      className={`border-gray-700 ${isMuted ? "text-red-400 bg-red-500/10" : "text-gray-300"}`}
                      onClick={() => setIsMuted(!isMuted)}
                    >
                      {isMuted ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      title={recorder.isRecording ? "Stop recording" : "Record call"}
                      className={`border-gray-700 ${recorder.isRecording ? "text-red-400 bg-red-500/10 border-red-700 animate-pulse" : "text-gray-300"}`}
                      onClick={handleToggleRecording}
                    >
                      {recorder.isRecording ? <Square className="w-4 h-4 fill-current" /> : <Disc className="w-4 h-4" />}
                      <span className="ml-1.5 text-xs">{recorder.isRecording ? "Stop Rec" : "Record"}</span>
                    </Button>
                  </div>

                  <Textarea
                    value={callNotes}
                    onChange={(e) => setCallNotes(e.target.value)}
                    placeholder="Call notes..."
                    className="bg-gray-800 border-gray-700 text-white min-h-[60px]"
                  />
                  <Button className="w-full bg-red-600 hover:bg-red-700" onClick={handleEndCall}>
                    <PhoneOff className="w-4 h-4 mr-2" /> End Call
                  </Button>
                </div>
              )}

              {callStatus === "disposition" && (
                <div className="space-y-3">
                  <div className="text-center py-2">
                    <p className="text-lg font-semibold text-white">Call Ended</p>
                    <p className="text-gray-400 font-mono">{formatDuration(duration)}</p>
                  </div>

                  {/* Recording playback */}
                  {recorder.audioUrl && (
                    <div className="bg-gray-800/60 border border-gray-700 rounded-lg p-3 space-y-2">
                      <div className="flex items-center justify-between">
                        <p className="text-xs font-medium text-gray-300 flex items-center gap-1.5">
                          <Disc className="w-3.5 h-3.5 text-red-400" /> Call Recording ({formatDuration(recordingDuration)})
                        </p>
                        <a
                          href={recorder.audioUrl}
                          download={`call-recording-${activeCallId ?? "call"}.webm`}
                          className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1"
                        >
                          <Download className="w-3 h-3" /> Download
                        </a>
                      </div>
                      <audio controls src={recorder.audioUrl} className="w-full h-9" />
                      <p className="text-[10px] text-gray-500">Recording is saved automatically when you select a result.</p>
                    </div>
                  )}

                  <label className="text-sm font-medium text-gray-300">Select Result</label>
                  <div className="grid grid-cols-2 gap-2 max-h-[140px] overflow-y-auto pr-1">
                    {dispositions.map((disp: any) => (
                      <Button
                        key={disp.id}
                        size="sm"
                        onClick={() => handleDisposition(disp.id.toString())}
                        className="bg-gray-800 text-white hover:bg-gray-700 justify-start"
                      >
                        {getDispIcon(disp.category)}
                        <span className="ml-1 truncate">{disp.label}</span>
                      </Button>
                    ))}
                  </div>
                </div>
              )}

              {callStatus === "idle" && (
                <div className="text-center py-8">
                  {nextCampaignLead ? (
                    <p className="text-gray-400 animate-pulse">Preparing next call...</p>
                  ) : (
                    <p className="text-gray-500 text-sm">All leads in this campaign queue have been dialed.</p>
                  )}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Session Stats */}
          <Card className="bg-gray-900 border-gray-800">
            <CardContent className="p-5 space-y-4">
              <div className="text-center pb-3 border-b border-gray-800">
                <Clock className="w-6 h-6 text-gray-500 mx-auto mb-1" />
                <p className="text-2xl font-bold text-white font-mono">{formatDuration(duration)}</p>
                <p className="text-xs text-gray-400">Current Call Duration</p>
              </div>
              <div>
                <h4 className="text-sm font-medium text-gray-300 mb-2">Campaign Queue Metrics</h4>
                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Total Leads</span>
                    <span className="text-white font-medium">{progressTotal}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Completed Calls</span>
                    <span className="text-green-400 font-medium">{progressCompleted}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Pending Leads</span>
                    <span className="text-amber-400 font-medium">{campaignProgress?.pending || 0}</span>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {!isRunning && (
        <Card className="bg-gray-900 border-gray-800">
          <CardContent className="p-12 text-center">
            <Radio className="w-16 h-16 text-gray-600 mx-auto mb-4" />
            <h3 className="text-xl font-semibold text-white mb-2">Auto Dialer Ready</h3>
            <p className="text-gray-400 mb-4 max-w-md mx-auto">
              Select a campaign and click Start to begin automated calling. The dialer will sequentially process leads and automatically move to the next after each call.
            </p>
            <div className="flex gap-4 justify-center text-sm text-gray-500">
              <span className="flex items-center gap-1"><CheckCircle2 className="w-4 h-4" /> Auto-advance leads</span>
              <span className="flex items-center gap-1"><BarChart3 className="w-4 h-4" /> Track dispositions</span>
              <span className="flex items-center gap-1"><SkipForward className="w-4 h-4" /> Resume from last</span>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState } from "react";
import { useAuth } from "@/hooks/useAuth";
import { trpc } from "@/providers/trpc";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Phone,
  PhoneCall,
  PhoneOff,
  Search,
  Download,
  Clock,
  Building,
  Mic,
  Filter,
} from "lucide-react";

export default function CallLogsPage() {
  const { user } = useAuth();
  const companyId = user?.companyId || 1;
  const isAdmin = user?.role === "admin" || user?.role === "superadmin";

  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all");

  // Load Calls Logs
  const { data: adminLogsData } = trpc.calls.list.useQuery(
    { companyId },
    { enabled: isAdmin }
  );

  const { data: callerLogsData } = trpc.calls.myCalls.useQuery(
    {},
    { enabled: !isAdmin }
  );

  const rawLogs = isAdmin 
    ? (Array.isArray(adminLogsData) ? adminLogsData : (adminLogsData as any)?.items || [])
    : (Array.isArray(callerLogsData) ? callerLogsData : (callerLogsData as any)?.items || []);

  // Load supporting lists to resolve names
  const { data: users = [] } = trpc.user.list.useQuery(undefined, { enabled: isAdmin });
  const { data: dispositions = [] } = trpc.calls.dispositions.useQuery({ companyId });

  // Lead details resolver matching db.json initial seed
  const getLeadDetails = (leadId: number) => {
    const leadsMap: Record<number, { name: string; company: string }> = {
      1: { name: "Sundar Pichai", company: "Google" },
      2: { name: "Satya Nadella", company: "Microsoft" },
      3: { name: "Tim Cook", company: "Apple" },
      4: { name: "Mark Zuckerberg", company: "Meta" }
    };
    return leadsMap[leadId] || { name: `Lead #${leadId}`, company: "Enterprise Target" };
  };

  const filtered = rawLogs.filter((log: any) => {
    if (statusFilter !== "all" && log.status !== statusFilter) return false;
    if (typeFilter !== "all" && log.type !== typeFilter) return false;

    const lead = getLeadDetails(log.leadId);
    const caller = users.find((u: any) => u.id === log.callerId);
    const callerName = caller?.name || `Caller #${log.callerId}`;

    if (search) {
      const q = search.toLowerCase();
      return (
        lead.name.toLowerCase().includes(q) ||
        lead.company.toLowerCase().includes(q) ||
        log.toNumber.includes(q) ||
        callerName.toLowerCase().includes(q)
      );
    }
    return true;
  });

  const formatDuration = (seconds: number) => {
    if (!seconds) return "-";
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}m ${secs}s`;
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "connected":
      case "completed":
        return <PhoneCall className="w-4 h-4 text-green-400" />;
      case "no_answer":
        return <PhoneOff className="w-4 h-4 text-amber-400" />;
      case "failed":
        return <PhoneOff className="w-4 h-4 text-red-400" />;
      default:
        return <Phone className="w-4 h-4 text-gray-400" />;
    }
  };

  const getDispositionBadge = (dispId: number | null) => {
    if (!dispId) return <Badge className="bg-gray-500/20 text-gray-400 border-0">No Outcome</Badge>;
    const dispObj = dispositions.find((d: any) => d.id === dispId);
    const label = dispObj?.label || `Outcome #${dispId}`;
    const category = dispObj?.category || "custom";

    const colors: Record<string, string> = {
      connected: "bg-green-500/20 text-green-400",
      not_interested: "bg-red-500/20 text-red-400",
      no_answer: "bg-amber-500/20 text-amber-400",
      callback: "bg-purple-500/20 text-purple-400",
      machine: "bg-blue-500/20 text-blue-400",
      converted: "bg-emerald-500/20 text-emerald-400",
      wrong_number: "bg-pink-500/20 text-pink-400",
      dnc: "bg-red-800/20 text-red-400",
    };

    return <Badge className={`${colors[category] || "bg-gray-500/20 text-gray-400"} border-0`}>{label}</Badge>;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Call Logs</h1>
          <p className="text-gray-400 mt-1">Complete history of all calls with recordings</p>
        </div>
        <Button variant="outline" className="border-gray-700 text-gray-300 hover:text-white hover:bg-gray-800">
          <Download className="w-4 h-4 mr-2" /> Export
        </Button>
      </div>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
          <Input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search by lead, company, or phone..."
            className="pl-10 bg-gray-900 border-gray-800 text-white"
          />
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-36 bg-gray-900 border-gray-800 text-white">
            <Filter className="w-4 h-4 mr-2" />
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent className="bg-gray-900 border-gray-800">
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="connected">Connected</SelectItem>
            <SelectItem value="completed">Completed</SelectItem>
            <SelectItem value="no_answer">No Answer</SelectItem>
            <SelectItem value="failed">Failed</SelectItem>
          </SelectContent>
        </Select>
        <Select value={typeFilter} onValueChange={setTypeFilter}>
          <SelectTrigger className="w-36 bg-gray-900 border-gray-800 text-white">
            <Phone className="w-4 h-4 mr-2" />
            <SelectValue placeholder="Type" />
          </SelectTrigger>
          <SelectContent className="bg-gray-900 border-gray-800">
            <SelectItem value="all">All Types</SelectItem>
            <SelectItem value="manual">Manual</SelectItem>
            <SelectItem value="auto">Auto</SelectItem>
            <SelectItem value="ai">AI</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Card className="bg-gray-900 border-gray-800">
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-gray-800">
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Lead</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Caller</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Type</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Status</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Disposition</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Duration</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Recording</th>
                  <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Time</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((log: any) => {
                  const lead = getLeadDetails(log.leadId);
                  const caller = users.find((u: any) => u.id === log.callerId);
                  const callerName = caller?.name || `Caller #${log.callerId}`;

                  return (
                    <tr key={log.id} className="border-b border-gray-800/50 hover:bg-gray-800/30">
                      <td className="px-4 py-3">
                        <div>
                          <div className="flex items-center gap-2">
                            <span className="text-sm font-medium text-white">{lead.name}</span>
                            {getStatusIcon(log.status)}
                          </div>
                          <div className="flex items-center gap-2 text-xs text-gray-500">
                            <Building className="w-3 h-3" /> {lead.company}
                            <Phone className="w-3 h-3 ml-1" /> {log.toNumber}
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-sm text-gray-400">{callerName}</td>
                      <td className="px-4 py-3">
                        <Badge variant="outline" className="border-gray-700 text-gray-400 capitalize text-xs">{log.type}</Badge>
                      </td>
                      <td className="px-4 py-3">
                        <Badge className={
                          (log.status === "connected" || log.status === "completed") ? "bg-green-500/20 text-green-400" :
                          log.status === "no_answer" ? "bg-amber-500/20 text-amber-400" :
                          "bg-red-500/20 text-red-400"
                        }>
                          {log.status}
                        </Badge>
                      </td>
                      <td className="px-4 py-3">{getDispositionBadge(log.dispositionId)}</td>
                      <td className="px-4 py-3 text-sm text-gray-400">
                        <span className="flex items-center gap-1">
                          <Clock className="w-3 h-3" /> {formatDuration(log.duration)}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        {log.recordingUrl ? (
                          <a 
                            href={log.recordingUrl} 
                            target="_blank" 
                            rel="noreferrer"
                            className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1"
                          >
                            <Mic className="w-4 h-4" /> Play
                          </a>
                        ) : (
                          <span className="text-xs text-gray-600">None</span>
                        )}
                      </td>
                      <td className="px-4 py-3 text-sm text-gray-500 font-mono">
                        {log.createdAt ? new Date(log.createdAt).toLocaleString() : "Never"}
                      </td>
                    </tr>
                  );
                })}
                {filtered.length === 0 && (
                  <tr>
                    <td colSpan={8} className="text-center py-8 text-gray-500">
                      No call logs found.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { useNavigate } from "react-router";
import { trpc } from "@/providers/trpc";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Progress } from "@/components/ui/progress";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Phone,
  Plus,
  Radio,
  Pause,
  Play,
  BarChart3,
  List,
  Clock,
  Users,
  Trash2,
  PhoneCall,
} from "lucide-react";

export default function CampaignsPage() {
  const navigate = useNavigate();
  const [showCreate, setShowCreate] = useState(false);

  // Form states for new campaign
  const [newName, setNewName] = useState("");
  const [newType, setNewType] = useState<"auto" | "manual" | "ai" | "sms">("auto");
  const [selectedListId, setSelectedListId] = useState<string>("");
  const [dailyStart, setDailyStart] = useState("09:00");
  const [dailyEnd, setDailyEnd] = useState("18:00");

  // Load Campaigns and Lead Lists from backend
  const { data: campaigns = [], refetch: refetchCampaigns } = trpc.campaign.list.useQuery();
  const { data: leadLists = [] } = trpc.lead.listLists.useQuery();

  // Mutations
  const createCampaignMutation = trpc.campaign.create.useMutation({
    onSuccess: () => {
      refetchCampaigns();
      setShowCreate(false);
      setNewName("");
      setNewType("auto");
      setSelectedListId("");
      setDailyStart("09:00");
      setDailyEnd("18:00");
    },
  });

  const startCampaignMutation = trpc.campaign.start.useMutation({
    onSuccess: () => refetchCampaigns(),
  });

  const pauseCampaignMutation = trpc.campaign.pause.useMutation({
    onSuccess: () => refetchCampaigns(),
  });

  const deleteCampaignMutation = trpc.campaign.delete.useMutation({
    onSuccess: () => refetchCampaigns(),
  });

  const handleCreateCampaign = async () => {
    if (!newName.trim() || !selectedListId) return;
    try {
      await createCampaignMutation.mutateAsync({
        name: newName,
        type: newType,
        leadListId: parseInt(selectedListId),
        dailyStartTime: dailyStart,
        dailyEndTime: dailyEnd,
      });
    } catch (err) {
      console.error("Failed to create campaign:", err);
    }
  };

  const handleDeleteCampaign = async (id: number) => {
    if (!confirm("Are you sure you want to delete this campaign?")) return;
    try {
      await deleteCampaignMutation.mutateAsync({ id });
    } catch (err) {
      console.error("Failed to delete campaign:", err);
    }
  };

  const getStatusBadge = (status: string) => {
    const colors: Record<string, string> = {
      running: "bg-green-500/20 text-green-400",
      paused: "bg-amber-500/20 text-amber-400",
      completed: "bg-blue-500/20 text-blue-400",
      draft: "bg-gray-500/20 text-gray-400",
      scheduled: "bg-purple-500/20 text-purple-400",
    };
    return <Badge className={`${colors[status] || "bg-gray-500/20"} border-0 capitalize`}>{status}</Badge>;
  };

  const getTypeBadge = (type: string) => {
    const icons: Record<string, React.ReactNode> = {
      auto: <Radio className="w-3 h-3" />,
      manual: <PhoneCall className="w-3 h-3" />,
      ai: <BarChart3 className="w-3 h-3" />,
      sms: <Phone className="w-3 h-3" />,
    };
    return (
      <span className="flex items-center gap-1 text-xs text-gray-400 capitalize">
        {icons[type]} {type}
      </span>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Campaigns</h1>
          <p className="text-gray-400 mt-1">Manage calling and messaging campaigns</p>
        </div>
        <Dialog open={showCreate} onOpenChange={setShowCreate}>
          <DialogTrigger asChild>
            <Button className="bg-blue-600 hover:bg-blue-700">
              <Plus className="w-4 h-4 mr-2" />
              New Campaign
            </Button>
          </DialogTrigger>
          <DialogContent className="bg-gray-900 border-gray-800 text-white max-w-lg">
            <DialogHeader>
              <DialogTitle>Create Campaign</DialogTitle>
            </DialogHeader>
            <div className="space-y-4 mt-4">
              <div>
                <Label className="text-gray-300">Campaign Name</Label>
                <Input 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="Enter campaign name" 
                  className="bg-gray-800 border-gray-700 text-white mt-1" 
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-gray-300">Type</Label>
                  <Select value={newType} onValueChange={(v: any) => setNewType(v)}>
                    <SelectTrigger className="bg-gray-800 border-gray-700 text-white mt-1">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-gray-800 border-gray-700">
                      <SelectItem value="auto">Auto Dialer</SelectItem>
                      <SelectItem value="manual">Manual</SelectItem>
                      <SelectItem value="ai">AI Agent</SelectItem>
                      <SelectItem value="sms">SMS</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label className="text-gray-300">Lead List</Label>
                  <Select value={selectedListId} onValueChange={setSelectedListId}>
                    <SelectTrigger className="bg-gray-800 border-gray-700 text-white mt-1">
                      <SelectValue placeholder="Select list" />
                    </SelectTrigger>
                    <SelectContent className="bg-gray-800 border-gray-700">
                      {leadLists.map((l: any) => (
                        <SelectItem key={l.id} value={l.id.toString()}>{l.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-gray-300">Daily Start Time</Label>
                  <Input 
                    type="time" 
                    value={dailyStart}
                    onChange={(e) => setDailyStart(e.target.value)}
                    className="bg-gray-800 border-gray-700 text-white mt-1" 
                  />
                </div>
                <div>
                  <Label className="text-gray-300">Daily End Time</Label>
                  <Input 
                    type="time" 
                    value={dailyEnd}
                    onChange={(e) => setDailyEnd(e.target.value)}
                    className="bg-gray-800 border-gray-700 text-white mt-1" 
                  />
                </div>
              </div>
              <Button className="w-full bg-blue-600 hover:bg-blue-700" onClick={handleCreateCampaign}>
                Create Campaign
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {campaigns.map((campaign: any) => {
          const listName = leadLists.find((ll: any) => ll.id === campaign.leadListId)?.name || "Unknown List";
          const callersCount = Array.isArray(campaign.assignedCallers) ? campaign.assignedCallers.length : 0;
          const total = campaign.totalLeads || 0;
          const completed = campaign.completedLeads || 0;
          const percentage = total > 0 ? Math.round((completed / total) * 100) : 0;

          return (
            <Card key={campaign.id} className="bg-gray-900 border-gray-800">
              <CardContent className="p-5">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-lg bg-blue-500/10 flex items-center justify-center">
                      <Radio className="w-5 h-5 text-blue-400" />
                    </div>
                    <div>
                      <h3 className="text-base font-semibold text-white">{campaign.name}</h3>
                      <div className="flex items-center gap-3 mt-0.5">
                        {getTypeBadge(campaign.type)}
                        <span className="text-xs text-gray-500">
                          <List className="w-3 h-3 inline mr-1" />
                          {listName}
                        </span>
                      </div>
                    </div>
                  </div>
                  {getStatusBadge(campaign.status)}
                </div>

                <div className="flex items-center gap-4 text-sm text-gray-400 mb-3">
                  <span className="flex items-center gap-1">
                    <Users className="w-4 h-4" />
                    {callersCount} callers
                  </span>
                  <span className="flex items-center gap-1">
                    <Clock className="w-4 h-4" />
                    {campaign.dailyStartTime || "09:00"} - {campaign.dailyEndTime || "18:00"}
                  </span>
                  {campaign.startDate && (
                    <span className="flex items-center gap-1">
                      <Phone className="w-4 h-4" />
                      Started {new Date(campaign.startDate).toLocaleDateString()}
                    </span>
                  )}
                </div>

                <div className="mb-2">
                  <div className="flex items-center justify-between text-sm mb-1">
                    <span className="text-gray-400">
                      {completed.toLocaleString()} / {total.toLocaleString()} leads
                    </span>
                    <span className="text-white font-medium">
                      {percentage}%
                    </span>
                  </div>
                  <Progress
                    value={percentage}
                    className="h-2 bg-gray-800"
                  />
                </div>

                <div className="flex gap-2 mt-4">
                  {campaign.status === "running" ? (
                    <Button 
                      variant="outline" 
                      size="sm" 
                      onClick={() => pauseCampaignMutation.mutate({ id: campaign.id })}
                      className="border-amber-600/30 text-amber-400 hover:bg-amber-600/20"
                    >
                      <Pause className="w-4 h-4 mr-1" /> Pause
                    </Button>
                  ) : (campaign.status === "paused" || campaign.status === "draft") ? (
                    <Button 
                      variant="outline" 
                      size="sm" 
                      onClick={() => startCampaignMutation.mutate({ id: campaign.id })}
                      className="border-green-600/30 text-green-400 hover:bg-green-600/20"
                    >
                      <Play className="w-4 h-4 mr-1" /> Start
                    </Button>
                  ) : null}

                  {campaign.type === "auto" && campaign.status === "running" && (
                    <Button
                      size="sm"
                      className="bg-blue-600 hover:bg-blue-700"
                      onClick={() => navigate("/auto-dialer")}
                    >
                      <PhoneCall className="w-4 h-4 mr-1" /> Launch
                    </Button>
                  )}

                  <Button 
                    variant="ghost" 
                    size="sm" 
                    onClick={() => handleDeleteCampaign(campaign.id)}
                    className="text-gray-400 hover:text-red-400 ml-auto"
                  >
                    <Trash2 className="w-4 h-4" />
                  </Button>
                </div>
              </CardContent>
            </Card>
          );
        })}
        {campaigns.length === 0 && (
          <div className="col-span-2 text-center py-12 text-gray-500">
            No campaigns configured. Click "New Campaign" to get started.
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useAuth } from "@/hooks/useAuth";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { useNavigate } from "react-router";
import {
  Phone,
  Users,
  List,
  Radio,
  BarChart3,
  PhoneCall,
  TrendingUp,
  Headphones,
  ArrowRight,
  CalendarDays,
} from "lucide-react";

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const isAdmin = user?.role === "admin" || user?.role === "superadmin";
  const companyId = user?.companyId || 1;

  // ── Date Range Filter (Today / 7d / 30d / Custom) ──
  const [rangePreset, setRangePreset] = useState<"today" | "7d" | "30d" | "custom">("7d");
  const [customFrom, setCustomFrom] = useState("");
  const [customTo, setCustomTo] = useState("");

  const { dateFrom, dateTo, chartDays } = useMemo(() => {
    const now = new Date();
    const endOfToday = new Date(now); endOfToday.setHours(23, 59, 59, 999);
    if (rangePreset === "today") {
      const start = new Date(now); start.setHours(0, 0, 0, 0);
      return { dateFrom: start.toISOString(), dateTo: endOfToday.toISOString(), chartDays: 1 };
    }
    if (rangePreset === "7d") {
      const start = new Date(now); start.setDate(start.getDate() - 6); start.setHours(0, 0, 0, 0);
      return { dateFrom: start.toISOString(), dateTo: endOfToday.toISOString(), chartDays: 7 };
    }
    if (rangePreset === "30d") {
      const start = new Date(now); start.setDate(start.getDate() - 29); start.setHours(0, 0, 0, 0);
      return { dateFrom: start.toISOString(), dateTo: endOfToday.toISOString(), chartDays: 30 };
    }
    // custom
    const from = customFrom ? new Date(customFrom + "T00:00:00") : undefined;
    const to = customTo ? new Date(customTo + "T23:59:59.999") : undefined;
    const days = from && to ? Math.max(1, Math.ceil((to.getTime() - from.getTime()) / 86400000)) : 7;
    return {
      dateFrom: from?.toISOString(),
      dateTo: to?.toISOString(),
      chartDays: Math.min(days, 90),
    };
  }, [rangePreset, customFrom, customTo]);

  // Retrieve dashboard statistics for Admin (filtered by selected date range)
  const { data: adminStats } = trpc.report.dashboard.useQuery(
    { companyId, dateFrom, dateTo },
    { enabled: isAdmin }
  );

  // Retrieve call statistics for Callers
  const { data: callerStats } = trpc.calls.stats.useQuery(
    {},
    { enabled: !isAdmin }
  );

  // Retrieve call volume for Chart
  const { data: callVolume = [] } = trpc.report.callVolume.useQuery(
    { companyId, days: chartDays },
    { enabled: isAdmin }
  );

  const displayVolume = callVolume.length > 0 ? callVolume : [
    { date: "Mon", total: 45, connected: 32 },
    { date: "Tue", total: 52, connected: 38 },
    { date: "Wed", total: 38, connected: 25 },
    { date: "Thu", total: 61, connected: 48 },
    { date: "Fri", total: 55, connected: 41 },
    { date: "Sat", total: 28, connected: 18 },
    { date: "Sun", total: 35, connected: 24 },
  ];

  // Stats display mapping
  const stats = [
    { label: rangePreset === "today" ? "Calls Today" : "Total Calls (Range)", value: isAdmin ? (adminStats?.totalCalls?.toLocaleString() ?? "0") : (callerStats?.total?.toLocaleString() ?? "0"), change: "+12%", icon: Phone, color: "text-blue-400", bg: "bg-blue-500/10" },
    { label: "Connected", value: isAdmin ? (adminStats?.connectedCalls?.toLocaleString() ?? "0") : (callerStats?.connected?.toLocaleString() ?? "0"), change: "+8%", icon: PhoneCall, color: "text-green-400", bg: "bg-green-500/10" },
    { label: "Total Leads", value: isAdmin ? (adminStats?.totalLeads?.toLocaleString() ?? "0") : "-", change: "+24%", icon: List, color: "text-purple-400", bg: "bg-purple-500/10" },
    { label: "Active Campaigns", value: isAdmin ? (adminStats?.activeCampaigns?.toLocaleString() ?? "0") : "-", change: "+2", icon: Radio, color: "text-amber-400", bg: "bg-amber-500/10" },
    { label: "Callers", value: isAdmin ? (adminStats?.totalCallers?.toLocaleString() ?? "0") : "-", change: "+3", icon: Users, color: "text-cyan-400", bg: "bg-cyan-500/10" },
    { label: "Today's Calls", value: isAdmin ? (adminStats?.todayCalls?.toLocaleString() ?? "0") : (callerStats?.total?.toLocaleString() ?? "0"), change: "+18%", icon: TrendingUp, color: "text-rose-400", bg: "bg-rose-500/10" },
  ];

  const quickActions = [
    { label: "Make a Call", icon: PhoneCall, path: "/dialer", desc: "Start manual calling" },
    { label: "Auto Dialer", icon: Radio, path: "/auto-dialer", desc: "Launch campaign calls" },
    { label: "Upload Leads", icon: List, path: "/leads", desc: "Import new lead lists" },
    { label: "Live Monitor", icon: Headphones, path: "/monitoring", desc: "Listen to active calls" },
  ];

  const recentActivity = [
    { type: "call", message: "Call completed - John Smith (Connected)", time: "2 min ago", status: "success" },
    { type: "call", message: "Call ended - Sarah Johnson (Not Interested)", time: "5 min ago", status: "neutral" },
    { type: "lead", message: "New leads uploaded - Tech Companies List (500)", time: "15 min ago", status: "info" },
    { type: "campaign", message: "Campaign 'Summer Promo' started", time: "1 hr ago", status: "info" },
    { type: "call", message: "Call completed - Mike Davis (Interested)", time: "1 hr ago", status: "success" },
    { type: "call", message: "Call failed - Lisa Wilson (No Answer)", time: "2 hrs ago", status: "warning" },
  ];

  return (
    <div className="space-y-6">
      {/* Welcome */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Welcome back, {user?.name || "Admin"}</h1>
          <p className="text-gray-400 mt-1">
            {isAdmin
              ? "Here's what's happening with your dialer today"
              : "Ready to make some calls today?"}
          </p>
        </div>
        <div className="flex flex-col sm:flex-row gap-2 sm:items-center">
          {isAdmin && (
            <div className="flex items-center gap-1 bg-gray-900 border border-gray-800 rounded-lg p-1">
              <CalendarDays className="w-4 h-4 text-gray-500 ml-2 mr-1" />
              {([
                { key: "today", label: "Today" },
                { key: "7d", label: "7 Days" },
                { key: "30d", label: "1 Month" },
                { key: "custom", label: "Custom" },
              ] as const).map((r) => (
                <button
                  key={r.key}
                  onClick={() => setRangePreset(r.key)}
                  className={`px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                    rangePreset === r.key ? "bg-blue-600 text-white" : "text-gray-400 hover:text-white"
                  }`}
                >
                  {r.label}
                </button>
              ))}
            </div>
          )}
          <Button
            onClick={() => navigate("/dialer")}
            className="bg-blue-600 hover:bg-blue-700"
          >
            <PhoneCall className="w-4 h-4 mr-2" />
            Start Calling
          </Button>
        </div>
      </div>

      {/* Custom range pickers */}
      {isAdmin && rangePreset === "custom" && (
        <div className="flex flex-wrap items-center gap-2">
          <input
            type="date"
            value={customFrom}
            onChange={(e) => setCustomFrom(e.target.value)}
            className="bg-gray-900 border border-gray-800 rounded-md px-3 py-2 text-sm text-white"
          />
          <span className="text-gray-500 text-sm">to</span>
          <input
            type="date"
            value={customTo}
            onChange={(e) => setCustomTo(e.target.value)}
            className="bg-gray-900 border border-gray-800 rounded-md px-3 py-2 text-sm text-white"
          />
        </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
        {stats.map((stat) => (
          <Card key={stat.label} className="bg-gray-900 border-gray-800">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div className={`w-10 h-10 rounded-lg ${stat.bg} flex items-center justify-center`}>
                  <stat.icon className={`w-5 h-5 ${stat.color}`} />
                </div>
                <span className="text-xs font-medium text-green-400">{stat.change}</span>
              </div>
              <p className="text-2xl font-bold text-white mt-3">{stat.value}</p>
              <p className="text-sm text-gray-400">{stat.label}</p>
            </CardContent>
          </Card>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Quick Actions */}
        <Card className="bg-gray-900 border-gray-800 lg:col-span-2">
          <CardHeader>
            <CardTitle className="text-white text-lg">Quick Actions</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {quickActions.map((action) => (
                <Button
                  key={action.label}
                  variant="outline"
                  onClick={() => navigate(action.path)}
                  className="h-auto p-4 bg-gray-800/50 border-gray-700 hover:bg-gray-800 hover:border-gray-600 justify-start text-left"
                >
                  <div className={`w-10 h-10 rounded-lg bg-gray-700 flex items-center justify-center mr-3 flex-shrink-0`}>
                    <action.icon className="w-5 h-5 text-blue-400" />
                  </div>
                  <div>
                    <p className="text-white font-medium">{action.label}</p>
                    <p className="text-gray-400 text-xs">{action.desc}</p>
                  </div>
                  <ArrowRight className="w-4 h-4 text-gray-500 ml-auto" />
                </Button>
              ))}
            </div>
          </CardContent>
        </Card>

        {/* Recent Activity */}
        <Card className="bg-gray-900 border-gray-800">
          <CardHeader>
            <CardTitle className="text-white text-lg">Recent Activity</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {recentActivity.map((activity, i) => (
                <div key={i} className="flex items-start gap-3 pb-3 border-b border-gray-800 last:border-0">
                  <div className={`w-2 h-2 rounded-full mt-1.5 flex-shrink-0 ${
                    activity.status === "success" ? "bg-green-500" :
                    activity.status === "warning" ? "bg-amber-500" :
                    activity.status === "neutral" ? "bg-gray-500" :
                    "bg-blue-500"
                  }`} />
                  <div className="min-w-0">
                    <p className="text-sm text-gray-300 truncate">{activity.message}</p>
                    <p className="text-xs text-gray-500 mt-0.5">{activity.time}</p>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Performance Chart Placeholder */}
      <Card className="bg-gray-900 border-gray-800">
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle className="text-white text-lg">Call Performance</CardTitle>
          <Button variant="outline" size="sm" className="border-gray-700 text-gray-300 hover:text-white" onClick={() => navigate("/reports")}>
            <BarChart3 className="w-4 h-4 mr-2" />
            View Reports
          </Button>
        </CardHeader>
        <CardContent>
          <div className="h-64 flex items-end justify-around gap-2 px-4">
            {displayVolume.map((item: any, i: number) => {
              const total = item.total || 0;
              const connected = item.connected || 0;
              const maxVal = Math.max(...displayVolume.map((d: any) => d.total || 1));
              const heightTotal = (total / maxVal) * 200;
              const heightConnected = (connected / maxVal) * 200;
              const label = item.date.includes("-") ? item.date.split("-").slice(1).join("-") : item.date;

              return (
                <div key={i} className="flex-1 flex flex-col items-center gap-2">
                  <div className="w-full flex flex-col gap-1 items-center justify-end h-52">
                    <div
                      className="w-full bg-green-500/60 rounded-t hover:bg-green-500/80 transition-colors"
                      style={{ height: `${heightConnected}px` }}
                      title={`Connected: ${connected}`}
                    />
                    <div
                      className="w-full bg-blue-600/40 rounded-t hover:bg-blue-600/60 transition-colors"
                      style={{ height: `${Math.max(0, heightTotal - heightConnected)}px` }}
                      title={`Unconnected: ${total - connected}`}
                    />
                  </div>
                  <span className="text-xs text-gray-500">
                    {label}
                  </span>
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect, useRef, useMemo } from "react";
import { useAuth } from "@/hooks/useAuth";
import { useCallRecorder } from "@/hooks/useCallRecorder";
import { trpc } from "@/providers/trpc";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useTelnyxRTC } from "@/hooks/useTelnyxRTC";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Phone,
  PhoneCall,
  PhoneOff,
  Mic,
  MicOff,
  Pause,
  Play,
  SkipForward,
  Clock,
  User,
  Building,
  MapPin,
  Mail,
  Briefcase,
  Save,
  CheckCircle2,
  XCircle,
  Radio,
  Hash,
  Ban,
  MessageSquare,
  Disc,
  Square,
  Download,
} from "lucide-react";

export default function DialerPage() {
  const { user } = useAuth();
  const companyId = user?.companyId || 1;

  const [callStatus, setCallStatus] = useState<"idle" | "dialing" | "connected" | "ended">("idle");
  const [duration, setDuration] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [selectedDisposition, setSelectedDisposition] = useState<string | null>(null);
  const [callNotes, setCallNotes] = useState("");
  const [phoneNumber, setPhoneNumber] = useState("");
  const [customField, setCustomField] = useState("");
  const [showCustomField, setShowCustomField] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Active call ID returned by backend
  const [activeCallId, setActiveCallId] = useState<number | null>(null);
  const [callError, setCallError] = useState<string | null>(null);

  // ── Call Recording ──
  const recorder = useCallRecorder();
  const [savedRecordingDataUrl, setSavedRecordingDataUrl] = useState<string | null>(null);
  const [recordingDuration, setRecordingDuration] = useState(0);

  // Selected Lead List and Lead Index
  const [selectedListId, setSelectedListId] = useState<string>("");
  const [currentLeadIndex, setCurrentLeadIndex] = useState(0);

  // Queries
  const { data: leadLists = [] } = trpc.lead.listLists.useQuery();

  const { data: leadsResponse } = trpc.lead.list.useQuery(
    { leadListId: parseInt(selectedListId) || 0 },
    { enabled: !!selectedListId }
  );

  const leads = Array.isArray(leadsResponse) ? leadsResponse : (leadsResponse as any)?.items || [];
  const currentLead = leads[currentLeadIndex] || null;

  // ─── Editable lead fields + Excel-driven field selection ───
  const STANDARD_FIELDS: { key: string; label: string }[] = [
    { key: "firstName", label: "First Name" },
    { key: "lastName", label: "Last Name" },
    { key: "companyName", label: "Company" },
    { key: "designation", label: "Designation" },
    { key: "phone", label: "Phone" },
    { key: "phone2", label: "Phone 2" },
    { key: "email", label: "Email" },
    { key: "address", label: "Address" },
    { key: "city", label: "City" },
    { key: "state", label: "State" },
    { key: "country", label: "Country" },
    { key: "zipCode", label: "Zip Code" },
    { key: "website", label: "Website" },
    { key: "notes", label: "Notes" },
  ];

  const customFieldKeys = useMemo(() => {
    const set = new Set<string>();
    for (const l of leads as Array<{ customFields?: Record<string, unknown> }>) {
      const cf = l?.customFields;
      if (cf && typeof cf === "object") Object.keys(cf).forEach((k) => set.add(k));
    }
    return Array.from(set);
  }, [leads]);

  const allFields = useMemo(
    () => [...STANDARD_FIELDS, ...customFieldKeys.map((k) => ({ key: `cf:${k}`, label: k }))],
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [customFieldKeys],
  );

  const [displayFields, setDisplayFields] = useState<string[]>(() => {
    try {
      const s = localStorage.getItem("dialer.displayFields");
      if (s) return JSON.parse(s);
    } catch { /* ignore */ }
    return ["firstName", "lastName", "companyName", "phone", "email", "city", "state"];
  });
  useEffect(() => {
    try {
      localStorage.setItem("dialer.displayFields", JSON.stringify(displayFields));
    } catch { /* ignore */ }
  }, [displayFields]);

  const [fieldMenuOpen, setFieldMenuOpen] = useState(false);
  const [edited, setEdited] = useState<Record<string, string>>({});
  useEffect(() => {
    setEdited({});
  }, [currentLead?.id]);

  const utils = trpc.useUtils();
  const updateLeadMutation = trpc.lead.update.useMutation({
    onSuccess: () => utils.lead.list.invalidate(),
  });

  const toggleField = (key: string) =>
    setDisplayFields((prev) => (prev.includes(key) ? prev.filter((k) => k !== key) : [...prev, key]));

  const getFieldValue = (fieldKey: string): string => {
    if (fieldKey in edited) return edited[fieldKey];
    if (!currentLead) return "";
    if (fieldKey.startsWith("cf:")) {
      const v = (currentLead.customFields as Record<string, unknown> | undefined)?.[fieldKey.slice(3)];
      return v == null ? "" : String(v);
    }
    const v = (currentLead as Record<string, unknown>)[fieldKey];
    return v == null ? "" : String(v);
  };

  const setFieldValue = (fieldKey: string, val: string) =>
    setEdited((prev) => ({ ...prev, [fieldKey]: val }));

  const saveField = (fieldKey: string) => {
    if (!currentLead || !(fieldKey in edited)) return;
    const val = edited[fieldKey];
    if (fieldKey.startsWith("cf:")) {
      const k = fieldKey.slice(3);
      updateLeadMutation.mutate({
        id: currentLead.id,
        data: { customFields: { ...(currentLead.customFields || {}), [k]: val } },
      });
    } else {
      updateLeadMutation.mutate({ id: currentLead.id, data: { [fieldKey]: val } });
    }
  };

  const { data: dispositions = [] } = trpc.calls.dispositions.useQuery({ companyId });

  // Outbound caller IDs come from the configured Telnyx SIP trunk (caller-safe endpoint).
  const { data: dialerConfig } = trpc.integration.getDialerConfig.useQuery();

  // Browser calling via Telnyx WebRTC (requires a Telnyx Credential Connection).
  const rtc = useTelnyxRTC({
    enabled: Boolean(dialerConfig?.webrtc?.enabled),
    login: dialerConfig?.webrtc?.login || "",
    password: dialerConfig?.webrtc?.password || "",
  });
  const webrtcOn = Boolean(dialerConfig?.webrtc?.enabled);

  const callerNumbers = (dialerConfig?.fromNumbers ?? [])
    .filter((num: string) => !!num)
    .map((num: string) => ({
      label: dialerConfig?.connectionName ? `${dialerConfig.connectionName} (${num})` : num,
      value: num,
    }));

  const [selectedNumber, setSelectedNumber] = useState("");

  useEffect(() => {
    const preferred = dialerConfig?.defaultCallerId || callerNumbers[0]?.value || "";
    if (preferred && !selectedNumber) {
      setSelectedNumber(preferred);
    }
  }, [dialerConfig, callerNumbers, selectedNumber]);

  // Default select first lead list
  useEffect(() => {
    if (leadLists.length > 0 && !selectedListId) {
      setSelectedListId(leadLists[0].id.toString());
    }
  }, [leadLists, selectedListId]);

  // Sync dialed input number with current lead
  useEffect(() => {
    if (currentLead) {
      setPhoneNumber(currentLead.phone);
    }
  }, [currentLead]);

  // Call timer
  useEffect(() => {
    if (callStatus === "connected" && !isPaused) {
      timerRef.current = setInterval(() => setDuration((d) => d + 1), 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [callStatus, isPaused]);

  // Keep recorder mic in sync with the Mute button
  useEffect(() => {
    recorder.setMicMuted(isMuted);
    if (webrtcOn) rtc.setMuted(isMuted);
  }, [isMuted, recorder]);

  // Auto-start recording when a WebRTC call connects so BOTH sides (your mic +
  // the client's audio) are captured for the whole call — like a normal phone
  // call recording. A short delay lets the remote audio stream attach first.
  useEffect(() => {
    if (webrtcOn && rtc.callState === "active" && recorder.status === "inactive") {
      const id = setTimeout(() => {
        recorder.startRecording(rtc.getRemoteStream);
      }, 400);
      return () => clearTimeout(id);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [webrtcOn, rtc.callState]);

  // Mutations
  const initiateCallMutation = trpc.calls.initiate.useMutation();
  const updateStatusMutation = trpc.calls.updateStatus.useMutation();
  const endCallMutation = trpc.calls.endCall.useMutation();
  const saveRecordingMutation = trpc.calls.saveRecording.useMutation();

  const handleToggleRecording = async () => {
    if (recorder.status === "recording" || recorder.status === "paused") {
      const result = await recorder.stopRecording();
      if (result) {
        setSavedRecordingDataUrl(result.dataUrl);
        setRecordingDuration(result.duration);
      }
    } else {
      // Pass a getter so the recorder can attach the client's audio as soon as
      // the call provides it (captures both sides).
      await recorder.startRecording(webrtcOn ? rtc.getRemoteStream : undefined);
    }
  };

  // Stop any active recording and capture the audio (used on call end)
  const finalizeRecording = async (): Promise<{ dataUrl: string; duration: number } | null> => {
    if (recorder.status === "recording" || recorder.status === "paused") {
      const result = await recorder.stopRecording();
      if (result) {
        setSavedRecordingDataUrl(result.dataUrl);
        setRecordingDuration(result.duration);
        return { dataUrl: result.dataUrl, duration: result.duration };
      }
      return null;
    }
    if (savedRecordingDataUrl) {
      return { dataUrl: savedRecordingDataUrl, duration: recordingDuration };
    }
    return null;
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`;
  };

  const startCall = async () => {
    if (!phoneNumber) return;
    setCallError(null);
    setCallStatus("dialing");
    try {
      const activeCall = await initiateCallMutation.mutateAsync({
        leadId: currentLead?.id || 1,
        companyId,
        toNumber: phoneNumber,
        fromNumber: selectedNumber || undefined,
        type: "manual",
      });

      // If the provider (Telnyx) rejected the call, surface the reason instead
      // of pretending the call connected.
      if (activeCall.success === false) {
        setCallError(activeCall.error || "The call could not be placed through Telnyx.");
        setCallStatus("idle");
        return;
      }

      setActiveCallId(activeCall.id);

      // Browser calling: place a real call with two-way audio through Telnyx WebRTC.
      if (webrtcOn) {
        if (rtc.status !== "registered") {
          setCallError(rtc.error || "Browser calling is still connecting. Check SIP credentials in Settings → SIP Trunk, then try again.");
          setCallStatus("idle");
          return;
        }
        const ok = rtc.makeCall(phoneNumber, selectedNumber || dialerConfig?.defaultCallerId || "");
        if (!ok) {
          setCallError(rtc.error || "Could not start the browser call.");
          setCallStatus("idle");
          return;
        }
        setCallStatus("connected");
        setDuration(0);
        await updateStatusMutation.mutateAsync({ id: activeCall.id, status: "connected" });
        return;
      }

      // No live provider configured: advance the on-screen call timer so the
      // workflow (notes, disposition, recording) still works.
      setTimeout(async () => {
        setCallStatus("connected");
        setDuration(0);
        await updateStatusMutation.mutateAsync({
          id: activeCall.id,
          status: "connected",
        });
      }, 1500);
    } catch (err) {
      console.error("Failed to initiate call:", err);
      setCallError(err instanceof Error ? err.message : "Failed to initiate call.");
      setCallStatus("idle");
    }
  };

  const handleEndCall = async () => {
    if (webrtcOn) {
      rtc.hangup();
    }
    setCallStatus("ended");
    if (timerRef.current) clearInterval(timerRef.current);
    // Auto-stop and keep the recording when the call ends
    await finalizeRecording();
    if (activeCallId) {
      try {
        await updateStatusMutation.mutateAsync({
          id: activeCallId,
          status: "completed",
        });
      } catch (err) {
        console.error("Failed to update status on end call:", err);
      }
    }
  };

  const resetCall = () => {
    setCallStatus("idle");
    setDuration(0);
    setSelectedDisposition(null);
    setCallNotes("");
    setIsMuted(false);
    setIsPaused(false);
    setShowCustomField(false);
    setActiveCallId(null);
    recorder.resetRecording();
    setSavedRecordingDataUrl(null);
    setRecordingDuration(0);
  };

  const handleSaveAndNext = async () => {
    if (activeCallId) {
      try {
        const dispId = selectedDisposition ? parseInt(selectedDisposition) : undefined;
        const rec = await finalizeRecording();
        await endCallMutation.mutateAsync({
          id: activeCallId,
          dispositionId: dispId,
          duration,
          notes: callNotes,
          callDescription: callNotes,
          recordingUrl: rec?.dataUrl || undefined,
        });
        // Also persist a dedicated recording record
        if (rec?.dataUrl) {
          await saveRecordingMutation.mutateAsync({
            callId: activeCallId,
            recordingUrl: rec.dataUrl,
            duration: rec.duration,
            fileSize: recorder.audioBlob?.size,
            format: "webm",
          });
        }
      } catch (err) {
        console.error("Failed to save call disposition:", err);
      }
    }

    // Advance to next lead
    if (currentLeadIndex < leads.length - 1) {
      setCurrentLeadIndex((prev) => prev + 1);
    } else {
      setCurrentLeadIndex(0);
    }
    resetCall();
  };

  const handleDisposition = (dispId: string) => {
    setSelectedDisposition(dispId);
    if (dispId === "custom" || dispId === "10") {
      setShowCustomField(true);
    }
  };

  const handleDialPad = (digit: string) => {
    setPhoneNumber((prev) => prev + digit);
  };

  const dialPadDigits = ["1", "2", "3", "4", "5", "6", "7", "8", "9", "*", "0", "#"];

  // Render disposition icon helper
  const getDispIcon = (category: string) => {
    switch (category) {
      case "connected":
      case "converted":
        return <CheckCircle2 className="w-4 h-4" />;
      case "no_answer":
        return <XCircle className="w-4 h-4" />;
      case "machine":
      case "voicemail":
        return <Radio className="w-4 h-4" />;
      case "wrong_number":
        return <Hash className="w-4 h-4" />;
      default:
        return <Ban className="w-4 h-4" />;
    }
  };

  return (
    <div className="space-y-6 max-w-6xl mx-auto">
      {/* Remote audio sink for Telnyx WebRTC calls */}
      <audio id={rtc.remoteAudioId} autoPlay />
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Manual Dialer</h1>
          <p className="text-gray-400 mt-1">Make calls and manage call outcomes</p>
          {webrtcOn && (
            <p className="text-xs mt-1">
              <span className={
                rtc.status === "registered" ? "text-green-400"
                : rtc.status === "connecting" ? "text-yellow-400"
                : "text-red-400"
              }>
                ● Browser calling: {rtc.status === "registered" ? "ready" : rtc.status === "connecting" ? "connecting…" : "not connected"}
              </span>
              {rtc.error ? <span className="text-red-400"> — {rtc.error}</span> : null}
            </p>
          )}
        </div>
        {callStatus === "idle" && (
          <div className="flex flex-col sm:flex-row gap-2">
            <Select value={selectedNumber} onValueChange={setSelectedNumber}>
              <SelectTrigger className="w-56 bg-gray-900 border-gray-800 text-white">
                <SelectValue placeholder="Select Caller ID" />
              </SelectTrigger>
              <SelectContent className="bg-gray-900 border-gray-800 text-white">
                {callerNumbers.length ? (
                  callerNumbers.map((n: { label: string; value: string }) => (
                    <SelectItem key={n.value} value={n.value}>{n.label}</SelectItem>
                  ))
                ) : (
                  <SelectItem value="none" disabled>
                    No number configured — set one in Settings → SIP Trunk
                  </SelectItem>
                )}
              </SelectContent>
            </Select>
            <select
              value={selectedListId}
              onChange={(e) => {
                setSelectedListId(e.target.value);
                setCurrentLeadIndex(0);
              }}
              className="bg-gray-900 border border-gray-800 rounded-md px-3 py-2 text-white text-sm"
            >
              <option value="">Select Lead List...</option>
              {leadLists.map((ll: any) => (
                <option key={ll.id} value={ll.id.toString()}>{ll.name}</option>
              ))}
            </select>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left: Lead Info */}
        <Card className="bg-gray-900 border-gray-800">
          <CardContent className="p-5 space-y-4">
            {currentLead ? (
              <>
                <div className="flex items-center justify-between gap-3 pb-3 border-b border-gray-800">
                  <div className="flex items-center gap-3 min-w-0">
                    <div className="w-10 h-10 rounded-full bg-blue-600/20 flex items-center justify-center shrink-0">
                      <User className="w-5 h-5 text-blue-400" />
                    </div>
                    <div className="min-w-0">
                      <h3 className="text-base font-semibold text-white truncate">
                        {getFieldValue("firstName")} {getFieldValue("lastName") || (getFieldValue("companyName") || "Lead")}
                      </h3>
                      <p className="text-xs text-gray-500">Lead #{currentLead.id}</p>
                    </div>
                  </div>
                  {/* Field selector — choose which columns to show */}
                  <div className="relative shrink-0">
                    <Button
                      variant="outline"
                      size="sm"
                      className="border-gray-700 text-gray-300 hover:bg-gray-800 h-8"
                      onClick={() => setFieldMenuOpen((o) => !o)}
                    >
                      Fields
                    </Button>
                    {fieldMenuOpen && (
                      <>
                        <div className="fixed inset-0 z-10" onClick={() => setFieldMenuOpen(false)} />
                        <div className="absolute right-0 mt-1 z-20 w-60 max-h-80 overflow-auto bg-gray-900 border border-gray-700 rounded-md p-2 shadow-xl">
                          <p className="text-xs text-gray-400 px-1 pb-1 sticky top-0 bg-gray-900">Show these fields</p>
                          {allFields.map((f) => (
                            <label
                              key={f.key}
                              className="flex items-center gap-2 px-1 py-1 text-sm text-gray-300 hover:bg-gray-800 rounded cursor-pointer"
                            >
                              <input
                                type="checkbox"
                                className="accent-blue-500"
                                checked={displayFields.includes(f.key)}
                                onChange={() => toggleField(f.key)}
                              />
                              <span className="truncate">{f.label}</span>
                              {f.key.startsWith("cf:") && <span className="text-[10px] text-blue-400 ml-auto">Excel</span>}
                            </label>
                          ))}
                        </div>
                      </>
                    )}
                  </div>
                </div>

                <div className="space-y-2">
                  {displayFields.length === 0 && (
                    <p className="text-sm text-gray-500">No fields selected. Click "Fields" to choose which to show.</p>
                  )}
                  {displayFields.map((fk) => {
                    const f = allFields.find((x) => x.key === fk);
                    if (!f) return null;
                    return (
                      <div key={fk}>
                        <label className="text-xs text-gray-500">{f.label}</label>
                        {fk === "notes" ? (
                          <Textarea
                            value={getFieldValue(fk)}
                            onChange={(e) => setFieldValue(fk, e.target.value)}
                            onBlur={() => saveField(fk)}
                            className="bg-gray-800 border-gray-700 text-white mt-0.5 text-sm min-h-[60px]"
                          />
                        ) : (
                          <Input
                            value={getFieldValue(fk)}
                            onChange={(e) => setFieldValue(fk, e.target.value)}
                            onBlur={() => saveField(fk)}
                            className="bg-gray-800 border-gray-700 text-white mt-0.5 text-sm h-9"
                          />
                        )}
                      </div>
                    );
                  })}
                  {updateLeadMutation.isPending && <p className="text-xs text-gray-500">Saving…</p>}
                </div>
              </>
            ) : (
              <div className="text-center py-12 text-gray-500">
                No lead details available. Select a lead list (file) above with active records.
              </div>
            )}
          </CardContent>
        </Card>

        {/* Center: Call Interface */}
        <Card className="bg-gray-900 border-gray-800">
          <CardContent className="p-5">
            {callStatus === "idle" && (
              <div className="space-y-4">
                <div className="text-center py-4">
                  <div className="w-16 h-16 rounded-full bg-gray-800 flex items-center justify-center mx-auto mb-3">
                    <Phone className="w-8 h-8 text-gray-400" />
                  </div>
                  <p className="text-gray-400">Ready to call</p>
                </div>
                <Input
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                  placeholder="Enter phone number"
                  className="bg-gray-800 border-gray-700 text-white text-center text-lg"
                />
                <div className="grid grid-cols-3 gap-2">
                  {dialPadDigits.map((digit) => (
                    <button
                      key={digit}
                      onClick={() => handleDialPad(digit)}
                      className="h-12 rounded-lg bg-gray-800 text-white font-medium text-lg hover:bg-gray-700 transition-colors"
                    >
                      {digit}
                    </button>
                  ))}
                </div>
                {callError && (
                  <div className="text-sm rounded-md px-3 py-2 border bg-red-500/10 text-red-400 border-red-500/20">
                    {callError}
                  </div>
                )}
                <Button
                  className="w-full h-14 bg-green-600 hover:bg-green-700 text-lg"
                  onClick={startCall}
                  disabled={!phoneNumber}
                >
                  <PhoneCall className="w-5 h-5 mr-2" />
                  Call
                </Button>
              </div>
            )}

            {callStatus === "dialing" && (
              <div className="text-center py-12 space-y-4">
                <div className="w-20 h-20 rounded-full bg-blue-500/20 flex items-center justify-center mx-auto animate-pulse">
                  <Phone className="w-10 h-10 text-blue-400 animate-bounce" />
                </div>
                <div>
                  <p className="text-xl font-semibold text-white">Dialing...</p>
                  <p className="text-gray-400 mt-1">{phoneNumber}</p>
                  <p className="text-xs text-gray-500 mt-1">Calling from: {selectedNumber}</p>
                </div>
                <Button variant="outline" className="border-red-600/30 text-red-400 hover:bg-red-600/20" onClick={resetCall}>
                  <PhoneOff className="w-4 h-4 mr-2" /> Cancel
                </Button>
              </div>
            )}

            {(callStatus === "connected" || callStatus === "ended") && (
              <div className="space-y-4">
                {/* Call Status */}
                <div className="text-center">
                  <div className={`w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-2 ${
                    callStatus === "connected" ? "bg-green-500/20 animate-pulse" : "bg-gray-700"
                  }`}>
                    <Phone className={`w-8 h-8 ${callStatus === "connected" ? "text-green-400" : "text-gray-400"}`} />
                  </div>
                  <p className="text-2xl font-bold text-white font-mono">
                    {formatDuration(duration)}
                  </p>
                  <Badge className={callStatus === "connected" ? "bg-green-500/20 text-green-400 mt-2 animate-pulse" : "bg-gray-500/20 text-gray-400 mt-2"}>
                    {callStatus === "connected" ? "On Call" : "Call Ended"}
                  </Badge>
                  <p className="text-xs text-gray-500 mt-2 font-mono">Connected Line: {selectedNumber}</p>
                </div>

                {/* Recording indicator */}
                {recorder.isRecording && (
                  <div className="flex items-center justify-center gap-2 bg-red-500/10 border border-red-500/30 rounded-lg py-1.5 px-3">
                    <span className="relative flex h-2.5 w-2.5">
                      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75" />
                      <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-red-500" />
                    </span>
                    <span className="text-xs font-semibold text-red-400 tracking-wider">REC</span>
                    <span className="text-xs font-mono text-red-300">{formatDuration(recorder.recordingTime)}</span>
                  </div>
                )}
                {recorder.error && (
                  <p className="text-xs text-red-400 text-center bg-red-500/10 border border-red-500/30 rounded-md py-1.5 px-2">{recorder.error}</p>
                )}

                {/* Call Controls */}
                {callStatus === "connected" && (
                  <div className="flex justify-center gap-3">
                    <Button
                      variant="outline"
                      size="sm"
                      className={`border-gray-700 ${isMuted ? "text-red-400 bg-red-500/10" : "text-gray-300"}`}
                      onClick={() => setIsMuted(!isMuted)}
                    >
                      {isMuted ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      title={recorder.isRecording ? "Stop recording" : "Record call"}
                      className={`border-gray-700 ${recorder.isRecording ? "text-red-400 bg-red-500/10 border-red-700 animate-pulse" : "text-gray-300"}`}
                      onClick={handleToggleRecording}
                    >
                      {recorder.isRecording ? <Square className="w-4 h-4 fill-current" /> : <Disc className="w-4 h-4" />}
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      className={`border-gray-700 ${isPaused ? "text-amber-400 bg-amber-500/10" : "text-gray-300"}`}
                      onClick={() => setIsPaused(!isPaused)}
                    >
                      {isPaused ? <Play className="w-4 h-4" /> : <Pause className="w-4 h-4" />}
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      className="border-red-700 text-red-400 hover:bg-red-600/20"
                      onClick={handleEndCall}
                    >
                      <PhoneOff className="w-4 h-4 mr-1" /> End
                    </Button>
                  </div>
                )}

                {/* Recording Playback */}
                {callStatus === "ended" && recorder.audioUrl && (
                  <div className="bg-gray-800/60 border border-gray-700 rounded-lg p-3 space-y-2">
                    <div className="flex items-center justify-between">
                      <p className="text-xs font-medium text-gray-300 flex items-center gap-1.5">
                        <Disc className="w-3.5 h-3.5 text-red-400" /> Call Recording ({formatDuration(recordingDuration)})
                      </p>
                      <a
                        href={recorder.audioUrl}
                        download={`call-recording-${activeCallId ?? "call"}.webm`}
                        className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1"
                      >
                        <Download className="w-3 h-3" /> Download
                      </a>
                    </div>
                    <audio controls src={recorder.audioUrl} className="w-full h-9" />
                    <p className="text-[10px] text-gray-500">Recording will be saved with this call on "Save & Next".</p>
                  </div>
                )}

                {/* Call Notes */}
                <div>
                  <label className="text-sm font-medium text-gray-300 mb-1 block">Call Description</label>
                  <Textarea
                    value={callNotes}
                    onChange={(e) => setCallNotes(e.target.value)}
                    placeholder="Enter call notes..."
                    className="bg-gray-800 border-gray-700 text-white min-h-[80px]"
                  />
                </div>

                {/* Dispositions */}
                {callStatus === "ended" && (
                  <div>
                    <label className="text-sm font-medium text-gray-300 mb-2 block">Call Result</label>
                    <div className="grid grid-cols-2 gap-2 max-h-[160px] overflow-y-auto pr-1">
                      {dispositions.map((disp: any) => (
                        <Button
                          key={disp.id}
                          size="sm"
                          onClick={() => handleDisposition(disp.id.toString())}
                          className={`bg-gray-800 text-white hover:bg-gray-700 justify-start ${
                            selectedDisposition === disp.id.toString() ? "ring-2 ring-blue-500 bg-gray-700" : ""
                          }`}
                        >
                          {getDispIcon(disp.category)}
                          <span className="ml-1 truncate">{disp.label}</span>
                        </Button>
                      ))}
                    </div>
                    {showCustomField && (
                      <div className="mt-3">
                        <Input
                          value={customField}
                          onChange={(e) => setCustomField(e.target.value)}
                          placeholder="Enter custom result..."
                          className="bg-gray-800 border-gray-700 text-white"
                        />
                      </div>
                    )}
                    <div className="flex gap-2 mt-4">
                      <Button
                        variant="outline"
                        className="flex-1 border-gray-700 text-gray-300 hover:text-white"
                        onClick={() => {
                          if (currentLeadIndex < leads.length - 1) {
                            setCurrentLeadIndex((prev) => prev + 1);
                          } else {
                            setCurrentLeadIndex(0);
                          }
                          resetCall();
                        }}
                      >
                        <SkipForward className="w-4 h-4 mr-1" /> Skip
                      </Button>
                      <Button 
                        className="flex-1 bg-blue-600 hover:bg-blue-700" 
                        onClick={handleSaveAndNext}
                      >
                        <Save className="w-4 h-4 mr-1" /> Save & Next
                      </Button>
                    </div>
                  </div>
                )}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Right: Timer & Quick Info */}
        <Card className="bg-gray-900 border-gray-800">
          <CardContent className="p-5 space-y-4">
            <div className="text-center py-4 border-b border-gray-800">
              <Clock className="w-8 h-8 text-gray-500 mx-auto mb-2" />
              <p className="text-3xl font-bold text-white font-mono">{formatDuration(duration)}</p>
              <p className="text-sm text-gray-400 mt-1">Call Duration</p>
            </div>

            <div className="space-y-3">
              <h4 className="text-sm font-medium text-gray-300">Today's Stats</h4>
              <div className="grid grid-cols-2 gap-3">
                <div className="bg-gray-800/50 rounded-lg p-3 text-center">
                  <p className="text-xl font-bold text-white">{leads.length}</p>
                  <p className="text-xs text-gray-400">Total Leads</p>
                </div>
                <div className="bg-gray-800/50 rounded-lg p-3 text-center">
                  <p className="text-xl font-bold text-blue-400">{currentLeadIndex}</p>
                  <p className="text-xs text-gray-400">Position</p>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

