import { useState, useEffect } from "react";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Progress } from "@/components/ui/progress";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  MessageSquare,
  Plus,
  Send,
  Pause,
  Play,
  Phone,
  Clock,
  List,
} from "lucide-react";

export default function SMSCampaignsPage() {
  const [showCreate, setShowCreate] = useState(false);
  const [selectedLogCampaignId, setSelectedLogCampaignId] = useState<number | null>(null);

  // Form states
  const [newName, setNewName] = useState("");
  const [selectedListId, setSelectedListId] = useState<string>("");
  const [fromNum, setFromNum] = useState("+1-555-0199");
  const [template, setTemplate] = useState("");
  const [scheduleTime, setScheduleTime] = useState("");

  // ── Sending Settings ──
  const [sendWindowStart, setSendWindowStart] = useState("09:00");
  const [sendWindowEnd, setSendWindowEnd] = useState("18:00");
  const [dailyLimit, setDailyLimit] = useState("500");
  const [randomizeOrder, setRandomizeOrder] = useState(false);
  const [randomDelay, setRandomDelay] = useState(false);
  const [randomDelayMin, setRandomDelayMin] = useState("5");
  const [randomDelayMax, setRandomDelayMax] = useState("45");

  // Queries
  const { data: campaigns = [], refetch: refetchCampaigns } = trpc.sms.list.useQuery();
  const { data: leadLists = [] } = trpc.lead.listLists.useQuery();

  // Load logs for the selected campaign
  const { data: logs = [] } = trpc.sms.logs.useQuery(
    { campaignId: selectedLogCampaignId || 0 },
    { enabled: selectedLogCampaignId !== null }
  );

  // Set default log campaign
  useEffect(() => {
    if (campaigns.length > 0 && selectedLogCampaignId === null) {
      setSelectedLogCampaignId(campaigns[0].id);
    }
  }, [campaigns, selectedLogCampaignId]);

  // Mutations
  const createSMSMutation = trpc.sms.create.useMutation({
    onSuccess: () => {
      refetchCampaigns();
      setShowCreate(false);
      setNewName("");
      setSelectedListId("");
      setFromNum("+1-555-0199");
      setTemplate("");
      setScheduleTime("");
      setSendWindowStart("09:00");
      setSendWindowEnd("18:00");
      setDailyLimit("500");
      setRandomizeOrder(false);
      setRandomDelay(false);
      setRandomDelayMin("5");
      setRandomDelayMax("45");
    },
  });

  const sendSMSMutation = trpc.sms.send.useMutation({
    onSuccess: () => refetchCampaigns(),
  });

  const pauseSMSMutation = trpc.sms.pause.useMutation({
    onSuccess: () => refetchCampaigns(),
  });

  const resumeSMSMutation = trpc.sms.resume.useMutation({
    onSuccess: () => refetchCampaigns(),
  });

  const handleCreateSMS = async () => {
    if (!newName.trim() || !selectedListId || !template.trim()) return;
    // Validate sending window + limits
    if (sendWindowStart >= sendWindowEnd) {
      alert("Send window start time must be earlier than end time.");
      return;
    }
    const limit = parseInt(dailyLimit) || 0;
    if (limit <= 0) {
      alert("Daily message limit must be greater than 0.");
      return;
    }
    const dMin = parseInt(randomDelayMin) || 0;
    const dMax = parseInt(randomDelayMax) || 0;
    if (randomDelay && dMin >= dMax) {
      alert("Random delay minimum must be smaller than maximum.");
      return;
    }
    try {
      await createSMSMutation.mutateAsync({
        name: newName,
        leadListId: parseInt(selectedListId),
        messageTemplate: template,
        fromNumber: fromNum || undefined,
        scheduledAt: scheduleTime || undefined,
        settings: {
          sendWindowStart,
          sendWindowEnd,
          dailyLimit: limit,
          randomizeOrder,
          randomDelay,
          randomDelayMinSec: randomDelay ? dMin : undefined,
          randomDelayMaxSec: randomDelay ? dMax : undefined,
        },
      });
    } catch (err) {
      console.error("Failed to create SMS campaign:", err);
    }
  };

  const getStatusBadge = (status: string) => {
    const colors: Record<string, string> = {
      sending: "bg-green-500/20 text-green-400 animate-pulse",
      paused: "bg-amber-500/20 text-amber-400",
      completed: "bg-blue-500/20 text-blue-400",
      scheduled: "bg-purple-500/20 text-purple-400",
      draft: "bg-gray-500/20 text-gray-400",
    };
    return <Badge className={`${colors[status] || "bg-gray-500/20"} border-0 capitalize`}>{status}</Badge>;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">SMS Campaigns</h1>
          <p className="text-gray-400 mt-1">Create and manage SMS messaging campaigns</p>
        </div>
        <Dialog open={showCreate} onOpenChange={setShowCreate}>
          <DialogTrigger asChild>
            <Button className="bg-blue-600 hover:bg-blue-700">
              <Plus className="w-4 h-4 mr-2" /> New Campaign
            </Button>
          </DialogTrigger>
          <DialogContent className="bg-gray-900 border-gray-800 text-white max-w-lg max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Create SMS Campaign</DialogTitle>
            </DialogHeader>
            <div className="space-y-4 mt-4">
              <div>
                <Label className="text-gray-300">Campaign Name</Label>
                <Input 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="Enter campaign name" 
                  className="bg-gray-800 border-gray-700 text-white mt-1" 
                />
              </div>
              <div>
                <Label className="text-gray-300">Lead List</Label>
                <Select value={selectedListId} onValueChange={setSelectedListId}>
                  <SelectTrigger className="bg-gray-800 border-gray-700 text-white mt-1">
                    <SelectValue placeholder="Select list" />
                  </SelectTrigger>
                  <SelectContent className="bg-gray-800 border-gray-700">
                    {leadLists.map((l: any) => (
                      <SelectItem key={l.id} value={l.id.toString()}>{l.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label className="text-gray-300">From Number</Label>
                <Input 
                  value={fromNum}
                  onChange={(e) => setFromNum(e.target.value)}
                  placeholder="+1-555-0199" 
                  className="bg-gray-800 border-gray-700 text-white mt-1" 
                />
              </div>
              <div>
                <Label className="text-gray-300">Message Template</Label>
                <Textarea
                  value={template}
                  onChange={(e) => setTemplate(e.target.value)}
                  placeholder="Hi {firstName}, ..."
                  className="bg-gray-800 border-gray-700 text-white mt-1 min-h-[100px]"
                />
                <p className="text-xs text-gray-500 mt-1">Use {'{firstName}'}, {'{lastName}'}, {'{companyName}'} as variables</p>
              </div>
              <div>
                <Label className="text-gray-300">Schedule (optional)</Label>
                <Input 
                  type="datetime-local" 
                  value={scheduleTime}
                  onChange={(e) => setScheduleTime(e.target.value)}
                  className="bg-gray-800 border-gray-700 text-white mt-1" 
                />
              </div>
              {/* ─── Sending Settings ─── */}
              <div className="border border-gray-800 rounded-lg p-3 space-y-3">
                <Label className="text-gray-300 flex items-center gap-1.5">
                  <Clock className="w-4 h-4 text-blue-400" /> Sending Settings
                </Label>

                {/* Time window */}
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <Label className="text-gray-400 text-xs">Send Window Start</Label>
                    <Input
                      type="time"
                      value={sendWindowStart}
                      onChange={(e) => setSendWindowStart(e.target.value)}
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                  </div>
                  <div>
                    <Label className="text-gray-400 text-xs">Send Window End</Label>
                    <Input
                      type="time"
                      value={sendWindowEnd}
                      onChange={(e) => setSendWindowEnd(e.target.value)}
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-gray-500">Messages are only sent inside this time window each day.</p>

                {/* Daily limit */}
                <div>
                  <Label className="text-gray-400 text-xs">Daily Message Limit</Label>
                  <Input
                    type="number"
                    min={1}
                    value={dailyLimit}
                    onChange={(e) => setDailyLimit(e.target.value)}
                    placeholder="500"
                    className="bg-gray-800 border-gray-700 text-white mt-1"
                  />
                  <p className="text-[10px] text-gray-500 mt-0.5">Maximum messages this campaign can send per day.</p>
                </div>

                {/* Randomization */}
                <div className="space-y-2">
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={randomizeOrder}
                      onChange={(e) => setRandomizeOrder(e.target.checked)}
                      className="rounded border-gray-700 bg-gray-800 accent-blue-600"
                    />
                    <span className="text-xs text-gray-300">Randomize sending order (shuffle leads)</span>
                  </label>
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={randomDelay}
                      onChange={(e) => setRandomDelay(e.target.checked)}
                      className="rounded border-gray-700 bg-gray-800 accent-blue-600"
                    />
                    <span className="text-xs text-gray-300">Random delay between messages (more natural, avoids spam flags)</span>
                  </label>
                  {randomDelay && (
                    <div className="grid grid-cols-2 gap-3 pl-6">
                      <div>
                        <Label className="text-gray-400 text-xs">Min delay (sec)</Label>
                        <Input
                          type="number"
                          min={1}
                          value={randomDelayMin}
                          onChange={(e) => setRandomDelayMin(e.target.value)}
                          className="bg-gray-800 border-gray-700 text-white mt-1"
                        />
                      </div>
                      <div>
                        <Label className="text-gray-400 text-xs">Max delay (sec)</Label>
                        <Input
                          type="number"
                          min={2}
                          value={randomDelayMax}
                          onChange={(e) => setRandomDelayMax(e.target.value)}
                          className="bg-gray-800 border-gray-700 text-white mt-1"
                        />
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <Button className="w-full bg-blue-600 hover:bg-blue-700" onClick={handleCreateSMS} disabled={createSMSMutation.isPending}>
                {createSMSMutation.isPending ? "Creating..." : "Create Campaign"}
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <Tabs defaultValue="campaigns">
        <TabsList className="bg-gray-900 border border-gray-800">
          <TabsTrigger value="campaigns" className="data-[state=active]:bg-gray-800">Campaigns</TabsTrigger>
          <TabsTrigger value="logs" className="data-[state=active]:bg-gray-800">Message Logs</TabsTrigger>
        </TabsList>

        <TabsContent value="campaigns" className="mt-4 space-y-4">
          {campaigns.map((campaign: any) => {
            const listName = leadLists.find((ll: any) => ll.id === campaign.leadListId)?.name || "Unknown List";
            const total = campaign.totalMessages || 0;
            const sent = campaign.sentMessages || 0;
            const delivered = campaign.deliveredMessages || 0;
            const failed = campaign.failedMessages || 0;
            const replied = campaign.repliedMessages || 0;
            const percentage = total > 0 ? Math.round((sent / total) * 100) : 0;

            return (
              <Card key={campaign.id} className="bg-gray-900 border-gray-800">
                <CardContent className="p-5">
                  <div className="flex items-start justify-between mb-3">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-lg bg-green-500/10 flex items-center justify-center">
                        <MessageSquare className="w-5 h-5 text-green-400" />
                      </div>
                      <div>
                        <h3 className="text-base font-semibold text-white">{campaign.name}</h3>
                        <div className="flex items-center gap-2 mt-0.5">
                          {getStatusBadge(campaign.status)}
                          <span className="text-xs text-gray-500">
                            <List className="w-3 h-3 inline mr-1" />
                            {listName}
                          </span>
                        </div>
                      </div>
                    </div>
                    <div className="flex gap-1">
                      {campaign.status === "sending" && (
                        <Button 
                          variant="ghost" 
                          size="sm" 
                          onClick={() => pauseSMSMutation.mutate({ id: campaign.id })}
                          className="text-amber-400 hover:text-amber-300 h-8 px-2"
                        >
                          <Pause className="w-4 h-4" />
                        </Button>
                      )}
                      {campaign.status === "paused" && (
                        <Button 
                          variant="ghost" 
                          size="sm" 
                          onClick={() => resumeSMSMutation.mutate({ id: campaign.id })}
                          className="text-green-400 hover:text-green-300 h-8 px-2"
                        >
                          <Play className="w-4 h-4" />
                        </Button>
                      )}
                      {(campaign.status === "draft" || campaign.status === "scheduled") && (
                        <Button 
                          variant="ghost" 
                          size="sm" 
                          onClick={() => sendSMSMutation.mutate({ id: campaign.id })}
                          className="text-blue-400 hover:text-blue-300 h-8 px-2"
                        >
                          <Send className="w-4 h-4" />
                        </Button>
                      )}
                    </div>
                  </div>

                  <p className="text-sm text-gray-400 mb-3 line-clamp-2 bg-gray-800/50 rounded p-2">{campaign.messageTemplate}</p>

                  <div className="flex items-center gap-4 text-xs text-gray-500 mb-3">
                    <span className="flex items-center gap-1">
                      <Phone className="w-3 h-3" /> From: {campaign.fromNumber || "+1-555-0199"}
                    </span>
                    {campaign.scheduledAt && (
                      <span className="flex items-center gap-1">
                        <Clock className="w-3 h-3" /> Scheduled: {new Date(campaign.scheduledAt).toLocaleString()}
                      </span>
                    )}
                  </div>

                  <div className="mb-2">
                    <div className="flex items-center justify-between text-sm mb-1">
                      <span className="text-gray-400">{sent.toLocaleString()} / {total.toLocaleString()} sent</span>
                      <span className="text-white font-medium">
                        {percentage}%
                      </span>
                    </div>
                    <Progress
                      value={percentage}
                      className="h-2 bg-gray-800"
                    />
                  </div>

                  <div className="grid grid-cols-4 gap-2 mt-3">
                    <div className="bg-gray-800/50 rounded p-2 text-center">
                      <p className="text-sm font-semibold text-green-400">{delivered.toLocaleString()}</p>
                      <p className="text-xs text-gray-500">Delivered</p>
                    </div>
                    <div className="bg-gray-800/50 rounded p-2 text-center">
                      <p className="text-sm font-semibold text-blue-400">{sent.toLocaleString()}</p>
                      <p className="text-xs text-gray-500">Sent</p>
                    </div>
                    <div className="bg-gray-800/50 rounded p-2 text-center">
                      <p className="text-sm font-semibold text-red-400">{failed.toLocaleString()}</p>
                      <p className="text-xs text-gray-500">Failed</p>
                    </div>
                    <div className="bg-gray-800/50 rounded p-2 text-center">
                      <p className="text-sm font-semibold text-purple-400">{replied.toLocaleString()}</p>
                      <p className="text-xs text-gray-500">Replies</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })}
          {campaigns.length === 0 && (
            <div className="text-center py-12 text-gray-500">
              No SMS campaigns configured. Click "New Campaign" to create one.
            </div>
          )}
        </TabsContent>

        <TabsContent value="logs" className="mt-4">
          <div className="flex items-center gap-3 mb-4">
            <Label className="text-gray-300 text-sm whitespace-nowrap">Select Campaign:</Label>
            <select
              value={selectedLogCampaignId || ""}
              onChange={(e) => setSelectedLogCampaignId(parseInt(e.target.value) || null)}
              className="bg-gray-900 border border-gray-800 rounded-md px-3 py-2 text-white text-sm"
            >
              <option value="">Choose campaign...</option>
              {campaigns.map((c: any) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>
          <Card className="bg-gray-900 border-gray-800">
            <CardHeader className="flex flex-row items-center justify-between">
              <CardTitle className="text-white text-base">Message Logs</CardTitle>
            </CardHeader>
            <CardContent className="p-0">
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="border-b border-gray-800">
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">To</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Message</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Status</th>
                      <th className="text-left px-4 py-3 text-sm font-medium text-gray-400">Sent At</th>
                    </tr>
                  </thead>
                  <tbody>
                    {logs.map((log: any) => (
                      <tr key={log.id} className="border-b border-gray-800/50 hover:bg-gray-800/30">
                        <td className="px-4 py-3 text-sm text-gray-300">{log.toNumber}</td>
                        <td className="px-4 py-3 text-sm text-gray-400 max-w-xs truncate">{log.message}</td>
                        <td className="px-4 py-3">
                          <Badge className={
                            log.status === "delivered" ? "bg-green-500/20 text-green-400" :
                            log.status === "replied" ? "bg-purple-500/20 text-purple-400" :
                            log.status === "sent" ? "bg-blue-500/20 text-blue-400" :
                            "bg-red-500/20 text-red-400"
                          }>
                            {log.status}
                          </Badge>
                        </td>
                        <td className="px-4 py-3 text-sm text-gray-400">{log.sentAt ? new Date(log.sentAt).toLocaleString() : "Never"}</td>
                      </tr>
                    ))}
                    {logs.length === 0 && (
                      <tr>
                        <td colSpan={4} className="text-center py-8 text-gray-500">
                          No logs found for this campaign.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useAuth } from "@/hooks/useAuth";
import { trpc } from "@/providers/trpc";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
  Phone,
  Save,
  Trash2,
  Edit,
  Radio,
  CheckCircle,
  XCircle,
  Loader2,
  Plus,
  X,
  PhoneCall,
  PhoneIncoming,
} from "lucide-react";

type CredentialForm = {
  phoneNumber: string;
  sipUsername: string;
  sipPassword: string;
  apiKey: string;
  sipHost: string;
  connectionId: string;
  enabled: boolean;
};

const EMPTY_FORM: CredentialForm = {
  phoneNumber: "",
  sipUsername: "",
  sipPassword: "",
  apiKey: "",
  sipHost: "",
  connectionId: "",
  enabled: true,
};

type TestState = "idle" | "loading" | "ok" | "error";

type TestResult = {
  outgoing: TestState;
  incoming: TestState;
  outgoingMessage: string;
  incomingMessage: string;
};

export default function SettingsPage() {
  const { user } = useAuth();
  const isAdmin = user?.role === "admin" || user?.role === "superadmin";

  const telnyxQuery = trpc.integration.getTelnyx.useQuery(undefined, { enabled: isAdmin });
  const numbersQuery = trpc.integration.listPhoneNumbers.useQuery(undefined, { enabled: isAdmin });

  const testTelnyxMutation = trpc.integration.testTelnyx.useMutation();
  const saveTelnyxMutation = trpc.integration.saveTelnyx.useMutation({
    onSuccess: () => {
      telnyxQuery.refetch();
      numbersQuery.refetch();
    },
  });
  const addPhoneMutation = trpc.integration.addPhoneNumber.useMutation({
    onSuccess: () => numbersQuery.refetch(),
  });
  const removePhoneMutation = trpc.integration.removePhoneNumber.useMutation({
    onSuccess: () => numbersQuery.refetch(),
  });

  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [form, setForm] = useState<CredentialForm>(EMPTY_FORM);
  const [testResult, setTestResult] = useState<TestResult>({
    outgoing: "idle",
    incoming: "idle",
    outgoingMessage: "",
    incomingMessage: "",
  });
  const [saveStatus, setSaveStatus] = useState<{ type: "idle" | "ok" | "error"; message: string }>({
    type: "idle",
    message: "",
  });

  useEffect(() => {
    if (editingId !== null && telnyxQuery.data) {
      const saved = telnyxQuery.data;
      const num = (numbersQuery.data || []).find((n: { id: number }) => n.id === editingId);
      setForm({
        phoneNumber: (num as { number?: string })?.number || saved.defaultCallerId || "",
        sipUsername: saved.sipUsername || "",
        sipPassword: "",
        apiKey: "",
        sipHost: saved.sipHost || "",
        connectionId: saved.connectionId || "",
        enabled: saved.enabled ?? true,
      });
    }
  }, [editingId, telnyxQuery.data, numbersQuery.data]);

  // All required fields filled → show Test button
  const isFormComplete =
    form.phoneNumber.trim() !== "" &&
    form.sipUsername.trim() !== "" &&
    (form.sipPassword.trim() !== "" || (editingId !== null && telnyxQuery.data?.hasSipPassword)) &&
    (form.apiKey.trim() !== "" || !!telnyxQuery.data?.hasApiKey);

  const handleTest = async () => {
    setTestResult({
      outgoing: "loading",
      incoming: "loading",
      outgoingMessage: "Connecting to Telnyx…",
      incomingMessage: "Verifying SIP registration…",
    });

    try {
      const res = await testTelnyxMutation.mutateAsync({ apiKey: form.apiKey || undefined });

      if (res.ok) {
        setTestResult({
          outgoing: "ok",
          incoming: "ok",
          outgoingMessage: `Outgoing ready — ${res.connections.length} connection(s) found`,
          incomingMessage: "Incoming verified — SIP credentials accepted",
        });
      } else {
        setTestResult({
          outgoing: "error",
          incoming: "error",
          outgoingMessage: res.message || "Outgoing test failed",
          incomingMessage: "Could not verify incoming — check SIP credentials",
        });
      }
    } catch (e) {
      const msg = e instanceof Error ? e.message : "Connection failed";
      setTestResult({
        outgoing: "error",
        incoming: "error",
        outgoingMessage: msg,
        incomingMessage: "Could not verify incoming",
      });
    }
  };

  const handleSave = async () => {
    try {
      await saveTelnyxMutation.mutateAsync({
        apiKey: form.apiKey || undefined,
        connectionId: form.connectionId,
        connectionName: form.sipUsername,
        defaultCallerId: form.phoneNumber,
        sipUsername: form.sipUsername,
        sipPassword: form.sipPassword || undefined,
        sipHost: form.sipHost,
        webrtcEnabled: true,
        enabled: form.enabled,
      });

      if (editingId === null) {
        await addPhoneMutation.mutateAsync({
          number: form.phoneNumber,
          label: form.sipUsername,
        });
      }

      setSaveStatus({ type: "ok", message: "Credential saved successfully." });
      setTimeout(() => {
        setShowForm(false);
        setEditingId(null);
        setForm(EMPTY_FORM);
        setTestResult({ outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "" });
        setSaveStatus({ type: "idle", message: "" });
      }, 1200);
    } catch (e) {
      setSaveStatus({ type: "error", message: e instanceof Error ? e.message : "Failed to save." });
    }
  };

  const handleEdit = (id: number) => {
    setEditingId(id);
    setShowForm(true);
    setTestResult({ outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "" });
    setSaveStatus({ type: "idle", message: "" });
  };

  const handleCancelForm = () => {
    setShowForm(false);
    setEditingId(null);
    setForm(EMPTY_FORM);
    setTestResult({ outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "" });
    setSaveStatus({ type: "idle", message: "" });
  };

  const phoneNumbers: Array<{ id: number; number: string; label?: string; status: string }> =
    numbersQuery.data || [];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Settings</h1>
        <p className="text-gray-400 mt-1">Manage your Telnyx SIP Trunk configuration</p>
      </div>

      {user && (
        <div className="flex items-center gap-3 rounded-lg border border-gray-800 bg-gray-900 px-4 py-3">
          <div className="w-9 h-9 rounded-full bg-blue-600/20 flex items-center justify-center text-blue-300 font-semibold">
            {(user.name || user.email || "?").charAt(0).toUpperCase()}
          </div>
          <div className="min-w-0">
            <p className="text-sm text-white truncate">
              Signed in as <span className="font-semibold">{user.name || user.email}</span>
            </p>
            <p className="text-xs text-gray-500 truncate">
              {user.email}
              {user.email ? " · " : ""}
              <span className="uppercase tracking-wide text-gray-400">{user.role}</span>
            </p>
          </div>
          <span className="ml-auto flex items-center gap-1 text-xs text-green-400">
            <span className="w-2 h-2 rounded-full bg-green-400" /> Active
          </span>
        </div>
      )}

      {!isAdmin ? (
        <Card className="bg-gray-900 border-gray-800">
          <CardContent className="py-10 text-center text-gray-500">
            <Radio className="w-8 h-8 mx-auto mb-2 opacity-40" />
            <p className="text-sm">Admin access required to manage SIP trunk settings.</p>
          </CardContent>
        </Card>
      ) : (
        <Card className="bg-gray-900 border-gray-800">
          <CardHeader className="flex flex-row items-center justify-between">
            <CardTitle className="text-white text-base flex items-center gap-2">
              <Radio className="w-5 h-5 text-green-400" />
              Telnyx SIP Trunk
              {telnyxQuery.data?.enabled && telnyxQuery.data?.connectionId && (
                <span className="ml-2 px-2 py-0.5 rounded text-xs font-semibold bg-green-500/10 text-green-400 border border-green-500/20">
                  Connected
                </span>
              )}
            </CardTitle>
            {!showForm && (
              <Button
                size="sm"
                className="bg-blue-600 hover:bg-blue-700"
                onClick={() => {
                  setShowForm(true);
                  setEditingId(null);
                  setForm(EMPTY_FORM);
                  setSaveStatus({ type: "idle", message: "" });
                  setTestResult({ outgoing: "idle", incoming: "idle", outgoingMessage: "", incomingMessage: "" });
                }}
              >
                <Plus className="w-4 h-4 mr-1" /> Add Phone Number
              </Button>
            )}
          </CardHeader>

          <CardContent className="space-y-4">
            {/* Saved credentials list */}
            {!showForm && (
              <>
                {phoneNumbers.length === 0 ? (
                  <div className="text-center py-10 text-gray-500">
                    <Phone className="w-9 h-9 mx-auto mb-2 opacity-30" />
                    <p className="text-sm">No phone credentials yet.</p>
                    <p className="text-xs mt-1">Click "Add Phone Number" to configure your first SIP trunk line.</p>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {phoneNumbers.map((n) => (
                      <div
                        key={n.id}
                        className="flex items-center gap-3 px-4 py-3 rounded-lg border border-gray-800 bg-gray-800/30"
                      >
                        <div className="w-8 h-8 rounded-full bg-blue-600/20 flex items-center justify-center shrink-0">
                          <Phone className="w-4 h-4 text-blue-400" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="text-white font-medium">{n.number}</p>
                          {n.label && (
                            <p className="text-xs text-gray-400 mt-0.5">{n.label}</p>
                          )}
                        </div>
                        <span
                          className={`text-xs px-2 py-0.5 rounded font-medium shrink-0 ${
                            n.status === "active"
                              ? "bg-green-500/10 text-green-400"
                              : "bg-gray-700 text-gray-500"
                          }`}
                        >
                          {n.status === "active" ? "Active" : "Inactive"}
                        </span>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleEdit(n.id)}
                          className="h-8 w-8 p-0 text-gray-400 hover:text-white shrink-0"
                          title="Edit"
                        >
                          <Edit className="w-4 h-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => removePhoneMutation.mutate({ id: n.id })}
                          disabled={removePhoneMutation.isPending}
                          className="h-8 w-8 p-0 text-gray-400 hover:text-red-400 shrink-0"
                          title="Remove"
                        >
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}
              </>
            )}

            {/* Add / Edit form */}
            {showForm && (
              <div className="space-y-5 border border-gray-700 rounded-xl p-5 bg-gray-800/20">
                <div className="flex items-center justify-between">
                  <p className="text-sm font-semibold text-white">
                    {editingId !== null ? "Edit Phone Credential" : "New Phone Credential"}
                  </p>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={handleCancelForm}
                    className="h-7 w-7 p-0 text-gray-400 hover:text-white"
                  >
                    <X className="w-4 h-4" />
                  </Button>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <Label className="text-gray-300 text-sm">
                      Phone Number <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      value={form.phoneNumber}
                      onChange={(e) => setForm({ ...form, phoneNumber: e.target.value })}
                      placeholder="+15550001111"
                      disabled={editingId !== null}
                      className="bg-gray-800 border-gray-700 text-white mt-1 disabled:opacity-60"
                    />
                    <p className="text-xs text-gray-500 mt-1">E.164 format — e.g. +15550001111</p>
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">
                      SIP Username <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      value={form.sipUsername}
                      onChange={(e) => setForm({ ...form, sipUsername: e.target.value })}
                      placeholder="e.g. salesvora_agent"
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    <p className="text-xs text-gray-500 mt-1">From your Telnyx Credential Connection</p>
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">
                      SIP Password <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      type="password"
                      value={form.sipPassword}
                      onChange={(e) => setForm({ ...form, sipPassword: e.target.value })}
                      placeholder={
                        editingId !== null && telnyxQuery.data?.hasSipPassword
                          ? "saved — type to change"
                          : "SIP credential password"
                      }
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    {editingId !== null && telnyxQuery.data?.hasSipPassword && (
                      <p className="text-xs text-green-400 mt-1">Password saved. Leave blank to keep it.</p>
                    )}
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">
                      Telnyx API Key <span className="text-red-400">*</span>
                    </Label>
                    <Input
                      type="password"
                      value={form.apiKey}
                      onChange={(e) => setForm({ ...form, apiKey: e.target.value })}
                      placeholder={
                        telnyxQuery.data?.hasApiKey
                          ? `Saved: ${telnyxQuery.data.apiKeyPreview}`
                          : "KEYxxxxxxxxxxxxxxxxxxxxxxxx"
                      }
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    {telnyxQuery.data?.hasApiKey && (
                      <p className="text-xs text-green-400 mt-1">API key saved. Leave blank to keep it.</p>
                    )}
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">SIP Host</Label>
                    <Input
                      value={form.sipHost}
                      onChange={(e) => setForm({ ...form, sipHost: e.target.value })}
                      placeholder="yourname.sip.telnyx.com"
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                  </div>

                  <div>
                    <Label className="text-gray-300 text-sm">Connection ID</Label>
                    <Input
                      value={form.connectionId}
                      onChange={(e) => setForm({ ...form, connectionId: e.target.value })}
                      placeholder="e.g. 2985974513046390685"
                      className="bg-gray-800 border-gray-700 text-white mt-1"
                    />
                    <p className="text-xs text-gray-500 mt-1">From Telnyx → Voice → SIP Connections</p>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <div>
                    <Label className="text-gray-300 text-sm">Enable for outbound calls</Label>
                    <p className="text-xs text-gray-500">Routes real calls through this SIP connection</p>
                  </div>
                  <Switch
                    checked={form.enabled}
                    onCheckedChange={(v) => setForm({ ...form, enabled: v })}
                  />
                </div>

                {/* Test section — only visible once all required fields are filled */}
                {isFormComplete && (
                  <div className="border-t border-gray-700 pt-5 space-y-3">
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="text-sm font-semibold text-white">Test Phone Number</p>
                        <p className="text-xs text-gray-500 mt-0.5">
                          Verify outgoing and incoming connectivity before saving
                        </p>
                      </div>
                      <Button
                        onClick={handleTest}
                        disabled={testTelnyxMutation.isPending}
                        className="bg-green-600 hover:bg-green-700 shrink-0"
                        size="sm"
                      >
                        {testTelnyxMutation.isPending ? (
                          <>
                            <Loader2 className="w-4 h-4 mr-1 animate-spin" /> Testing…
                          </>
                        ) : (
                          "Test Connection"
                        )}
                      </Button>
                    </div>

                    {/* Test results */}
                    {(testResult.outgoing !== "idle" || testResult.incoming !== "idle") && (
                      <div className="space-y-2">
                        <TestResultRow
                          state={testResult.outgoing}
                          label="Outgoing Call"
                          message={testResult.outgoingMessage}
                          icon={<PhoneCall className="w-4 h-4 shrink-0" />}
                        />
                        <TestResultRow
                          state={testResult.incoming}
                          label="Incoming Call"
                          message={testResult.incomingMessage}
                          icon={<PhoneIncoming className="w-4 h-4 shrink-0" />}
                        />
                      </div>
                    )}
                  </div>
                )}

                {saveStatus.type !== "idle" && (
                  <div
                    className={`text-sm rounded-md px-3 py-2 border ${
                      saveStatus.type === "ok"
                        ? "bg-green-500/10 text-green-400 border-green-500/20"
                        : "bg-red-500/10 text-red-400 border-red-500/20"
                    }`}
                  >
                    {saveStatus.message}
                  </div>
                )}

                <div className="flex gap-2 pt-1">
                  <Button
                    onClick={handleSave}
                    disabled={saveTelnyxMutation.isPending || addPhoneMutation.isPending}
                    className="bg-blue-600 hover:bg-blue-700"
                  >
                    <Save className="w-4 h-4 mr-1" />
                    {saveTelnyxMutation.isPending || addPhoneMutation.isPending
                      ? "Saving…"
                      : "Save Credential"}
                  </Button>
                  <Button
                    variant="outline"
                    onClick={handleCancelForm}
                    className="border-gray-700 text-gray-300 hover:text-white"
                  >
                    Cancel
                  </Button>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

function TestResultRow({
  state,
  label,
  message,
  icon,
}: {
  state: TestState;
  label: string;
  message: string;
  icon: JSX.Element;
}) {
  const colorClass =
    state === "ok"
      ? "bg-green-500/10 border-green-500/20 text-green-400"
      : state === "error"
      ? "bg-red-500/10 border-red-500/20 text-red-400"
      : "bg-gray-800 border-gray-700 text-gray-300";

  return (
    <div className={`flex items-start gap-3 px-3 py-2.5 rounded-md border text-sm ${colorClass}`}>
      <span className="mt-0.5">{icon}</span>
      <span className="mt-0.5">
        {state === "loading" && <Loader2 className="w-4 h-4 animate-spin" />}
        {state === "ok" && <CheckCircle className="w-4 h-4" />}
        {state === "error" && <XCircle className="w-4 h-4" />}
      </span>
      <div>
        <p className="font-medium">{label}</p>
        <p className="text-xs opacity-80 mt-0.5">{message}</p>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useAuth } from "@/hooks/useAuth";
import { trpc } from "@/providers/trpc";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Users,
  Plus,
  Search,
  Phone,
  Mail,
  Shield,
  UserCircle,
  Eye,
  PauseCircle,
  Trash2,
} from "lucide-react";

export default function UsersPage() {
  const { user } = useAuth();
  const isAdmin = user?.role === "admin" || user?.role === "superadmin";
  const [search, setSearch] = useState("");
  const [showCreate, setShowCreate] = useState(false);
  const [newUser, setNewUser] = useState({
    name: "",
    email: "",
    phone: "",
    role: "caller" as string,
    unionId: "",
    dailyCallLimit: 200,
    password: "",
  });
  const [showEdit, setShowEdit] = useState(false);
  const [editingUser, setEditingUser] = useState<any>(null);
  const [editUserData, setEditUserData] = useState({
    name: "",
    email: "",
    phone: "",
    role: "caller" as string,
    dailyCallLimit: 200,
    password: "",
  });

  const { data: usersList = [], refetch } = trpc.user.list.useQuery(undefined, {
    enabled: isAdmin,
  });

  const createUserMutation = trpc.user.create.useMutation({
    onSuccess: () => {
      refetch();
      setShowCreate(false);
      setNewUser({
        name: "",
        email: "",
        phone: "",
        role: "caller",
        unionId: "",
        dailyCallLimit: 200,
        password: "",
      });
    },
  });

  const updateUserMutation = trpc.user.update.useMutation({
    onSuccess: () => {
      refetch();
    },
  });

  const handleCreateUser = async () => {
    if (!newUser.name || !newUser.email) return;
    try {
      await createUserMutation.mutateAsync({
        name: newUser.name,
        email: newUser.email,
        phone: newUser.phone || undefined,
        role: newUser.role as "admin" | "caller" | "viewer",
        unionId: newUser.unionId || undefined,
        dailyCallLimit: newUser.dailyCallLimit,
        password: newUser.password || undefined,
      });
    } catch (err) {
      console.error("Failed to create user:", err);
    }
  };

  const handleToggleStatus = async (id: number, currentStatus: string) => {
    try {
      const newStatus = currentStatus === "active" ? "suspended" : "active";
      await updateUserMutation.mutateAsync({
        id,
        data: { status: newStatus as any },
      });
    } catch (err) {
      console.error("Failed to update user status:", err);
    }
  };

  const handleEditClick = (u: any) => {
    setEditingUser(u);
    setEditUserData({
      name: u.name || "",
      email: u.email || "",
      phone: u.phone || "",
      role: u.role || "caller",
      dailyCallLimit: u.dailyCallLimit ?? 200,
      password: "",
    });
    setShowEdit(true);
  };

  const handleUpdateUser = async () => {
    if (!editingUser || !editUserData.name || !editUserData.email) return;
    try {
      await updateUserMutation.mutateAsync({
        id: editingUser.id,
        data: {
          name: editUserData.name,
          email: editUserData.email,
          phone: editUserData.phone || undefined,
          role: editUserData.role as "admin" | "caller" | "viewer" | "superadmin",
          dailyCallLimit: editUserData.dailyCallLimit,
          password: editUserData.password || undefined,
        },
      });
      setShowEdit(false);
      setEditingUser(null);
    } catch (err) {
      console.error("Failed to update user:", err);
    }
  };

  const deleteUserMutation = trpc.user.delete.useMutation({
    onSuccess: () => {
      refetch();
    },
  });

  const handleDeleteUser = async (id: number) => {
    if (confirm("Are you sure you want to delete this user? This action cannot be undone.")) {
      try {
        await deleteUserMutation.mutateAsync({ id });
      } catch (err) {
        console.error("Failed to delete user:", err);
      }
    }
  };

  const filteredUsers = usersList.filter(
    (u: any) =>
      u.name.toLowerCase().includes(search.toLowerCase()) ||
      u.email.toLowerCase().includes(search.toLowerCase())
  );

  const getRoleIcon = (role: string) => {
    switch (role) {
      case "admin": return <Shield className="w-4 h-4 text-amber-400" />;
      case "caller": return <Phone className="w-4 h-4 text-blue-400" />;
      case "viewer": return <Eye className="w-4 h-4 text-gray-400" />;
      default: return <UserCircle className="w-4 h-4" />;
    }
  };

